INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11001, 1, '🍳 줄 서서 먹는 한남동 찐맛집', '', '✨ 드디어 오픈! 셰프의 한식 다이닝\n🔥 지금 예약하면 에이드 1잔 무료\n📌 제철 식재료로 만든 건강한 한 끼\n▶ 네이버 예약하기', '', 290000.00, 1450),
(11002, 1, '🍰 품절대란! 생딸기 듬뿍 케이크', '', '🍓 매일 아침 구워내는 수제 디저트\n💖 입안 가득 퍼지는 달콤한 행복\n⚡ 선착순 20개 한정 판매 중!\n▶ 구경하러 가기', '', 1580000.00, 7900),
(11003, 1, '🍣 장인 정신! 오마카세 20% 할인', '', '🌊 매일 공수하는 초신선 식재료\n💎 프라이빗한 룸에서 즐기는 미식 여행\n📞 예약 마감 임박! 지금 클릭\n▶ 메뉴 보기', '', 970000.00, 4850),
(11004, 1, '🥩 육즙 폭발! 숙성 한우 특가전', '', '🐂 1% 등급 한우를 집에서 편하게\n💰 신규 가입 시 1만원 즉시 할인\n🚀 오늘 주문하면 내일 아침 도착!\n▶ 구매하기', '', 360000.00, 1800),
(11005, 1, '🍜 TV 방영 맛집! 밀키트 출시', '', '🏠 줄 서지 말고 집에서 즐기세요\n✨ 매장 맛 그대로 100% 재현\n📌 3팩 구매 시 무료배송 혜택\n▶ 더 보기', '', 1650000.00, 8250),
(11006, 1, '🍕 치즈 듬뿍! 신메뉴 출시 기념 1+1', '', '🧀 쏟아지는 치즈 폭포의 향연\n🔥 오직 이번 주말만 진행하는 이벤트\n⚡ 놓치면 무조건 후회하는 구성!\n▶ 주문하기', '', 1040000.00, 5200),
(11007, 1, '🥗 다이어트 식단 고민 끝! 정기구독', '', '🥑 영양사가 설계한 500kcal 미만 메뉴\n✨ 매일 새벽 문 앞까지 배달\n💰 첫 달 구독료 50% 반값 찬스\n▶ 신청하기', '', 430000.00, 2150),
(11008, 1, '☕ 분위기 깡패! 성수동 핫플 카페', '', '📸 인생샷 보장하는 감성 인테리어\n🍪 직접 구운 수제 쿠키 무료 증정\n✨ 주말 데이트 코스 고민 해결\n▶ 위치 확인', '', 1720000.00, 8600),
(11009, 1, '🍲 엄마 손맛 그대로! 정성 반찬', '', '📌 조미료 없이 만든 건강한 집반찬\n💎 20년 경력 찬모의 특급 레시피\n🚚 전국 택배 가능! 신선 배송\n▶ 주문하기', '', 1110000.00, 5550),
(11010, 1, '🍻 불금엔 치맥! 배달료 0원 이벤트', '', '🍗 겉바속촉 끝판왕 치킨 등장\n🍺 시원한 수제 맥주와 환상 조합\n🔥 단 3시간만 배달비 무료!\n▶ 주문하기', '', 500000.00, 2500),
(11011, 1, '🦀 밥도둑 간장게장 역대급 할인', '', '💎 살이 꽉 찬 프리미엄 연평도 꽃게\n💰 홈쇼핑 완판 기념 30% 세일\n📌 오늘만 이 가격, 놓치지 마세요!\n▶ 구매하기', '', 1790000.00, 8950),
(11012, 1, '🍔 수제버거의 품격! 육즙 가득 패티', '', '🔥 주문 즉시 굽는 불맛 가득 버거\n🥤 세트 업그레이드 쿠폰 증정\n✨ 한 번 맛보면 멈출 수 없는 맛\n▶ 매장 찾기', '', 1180000.00, 5900),
(11013, 1, '🍱 직장인 필수! 프리미엄 도시락', '', '🍱 매일 바뀌는 12첩 반찬 구성\n📌 단체 주문 시 추가 할인 혜택\n🚚 회사 앞까지 따뜻하게 배송\n▶ 상담받기', '', 570000.00, 2850),
(11014, 1, '🍦 아이스크림 덕후 소환! 신메뉴', '', '🍨 쫀득한 젤라또 식감 그대로\n✨ 입안에서 사르르 녹는 달콤함\n🎯 2+1 이벤트 진행 중!\n▶ 겟하세요', '', 1860000.00, 9300),
(11015, 1, '🥘 스트레스 풀리는 매콤 떡볶이', '', '🔥 중독성 강한 마법의 양념장\n🧀 치즈 폭탄 추가는 선택 아닌 필수\n💸 지금 주문하면 쿨피스 서비스!\n▶ 주문하기', '', 1250000.00, 6250),
(11016, 1, '🥐 빵지순례 필수! 소금빵 맛집', '', '🥖 겉은 바삭 속은 촉촉 버터 풍미\n✨ 오후 2시면 전량 매진 주의\n📌 택배 주문 드디어 오픈!\n▶ 예약하기', '', 640000.00, 3200),
(11017, 1, '🍷 와인과 어울리는 핑거푸드 셋트', '', '🍇 분위기 있는 홈파티 필수템\n🧀 치즈, 샤퀴테리 완벽 구성\n✨ 퀵배송으로 오늘 저녁 바로!\n▶ 쇼핑하기', '', 1930000.00, 9650),
(11018, 1, '🥬 신선함 그대로! 유기농 채소 박스', '', '🚜 산지 직송으로 더 저렴하게\n📌 환경을 생각하는 제로 웨이스트\n💰 정기 배송 시 매회 10% 할인\n▶ 신청하기', '', 1320000.00, 6600),
(11019, 1, '🍲 해장 끝판왕! 뜨끈한 국밥 한 그릇', '', '✨ 24시간 가마솥에서 우려낸 진국\n🔥 한입 먹는 순간 속이 풀리는 기적\n📌 포장 주문 시 양 2배 증정!\n▶ 매장 보기', '', 710000.00, 3550),
(11020, 1, '🦐 통통한 새우장! 입맛 돋우는 별미', '', '💎 비법 간장으로 짜지 않고 감칠맛\n🍚 따끈한 밥 위에 올려 먹으면 끝\n🚚 아이스박스 꼼꼼 포장 배송\n▶ 더 보기', '', 100000.00, 500),
(11021, 1, '🥟 육즙 가득 수제 만두 특가', '', '🥟 얇은 피 속 꽉 찬 고기 함량\n✨ 에어프라이어 10분이면 완성\n💰 5봉 묶음 구매 시 역대급 할인\n▶ 구매하기', '', 1390000.00, 6950),
(11022, 1, '🍛 카레 성지! 인도 현지 셰프 요리', '', '🇮🇳 현지 향신료의 깊은 풍미\n📌 난 무제한 리필 이벤트 중\n✨ 이색 데이트 코스로 강추!\n▶ 예약하기', '', 780000.00, 3900),
(11023, 1, '🍜 차원이 다른 자가제면 우동', '', '🥢 탱글탱글한 면발의 끝판왕\n🌊 깊고 진한 가쓰오부시 육수\n🔥 단 1주일! 면 추가 무료\n▶ 방문하기', '', 170000.00, 850),
(11024, 1, '🍩 도넛 덕후 필독! 비주얼 끝판왕', '', '🍩 예뻐서 못 먹는 수제 도넛\n✨ 선물용으로 인기 만점 세트\n📌 6개입 구매 시 아메리카노 1잔\n▶ 구경하기', '', 1460000.00, 7300),
(11025, 1, '🥓 캠핑 필수! 바베큐 밀키트 세트', '', '⛺ 캠핑장에서도 전문점 맛 그대로\n🥩 고기부터 소스, 채소까지 풀구성\n🚀 금요일 도착 보장 배송!\n▶ 준비하기', '', 850000.00, 4250),
(11026, 1, '🍲 보양식 특집! 전복 삼계탕', '', '✨ 기력 회복엔 역시 전복과 닭\n🔥 한정 수량 당일 제조 판매\n📌 부모님 선물용 보자기 포장 가능\n▶ 주문하기', '', 240000.00, 1200),
(11027, 1, '🌯 다이어터 주목! 닭가슴살 브리또', '', '🥑 맛있게 관리하는 식단의 즐거움\n🔥 전자레인지 2분이면 든든한 한 끼\n💰 대량 구매 시 최대 45% 할인\n▶ 쟁여두기', '', 1530000.00, 7650),
(11028, 1, '🍹 홈카페 완성! 과일청 원액', '', '🍋 비타민 가득 생과일 100%\n✨ 탄산수만 넣으면 에이드 완성\n🎁 답례품 판매 1위 기록 중!\n▶ 구매하기', '', 920000.00, 4600),
(11029, 1, '🥞 브런치 맛집! 폭신한 수플레', '', '☁️ 구름을 먹는 듯한 부드러운 식감\n🍓 계절 과일 토핑 듬뿍 추가\n✨ 이번 주말 힐링 플레이스\n▶ 예약하기', '', 310000.00, 1550),
(11030, 1, '🦞 럭셔리 랍스터 버터구이 홈세트', '', '🌊 바다의 풍미를 집에서 그대로\n💎 특별한 기념일 필수 준비물\n🔥 손질 완료! 굽기만 하세요\n▶ 주문하기', '', 1600000.00, 8000),
(11031, 1, '🥢 매콤달콤 닭갈비 춘천 현지의 맛', '', '🔥 철판에서 볶아먹는 바로 그 맛\n📌 우동사리 + 치즈 서비스 증정\n💰 매장가 대비 40% 저렴한 가격\n▶ 담으러 가기', '', 990000.00, 4950),
(11032, 1, '🍪 수제 쿠키 답례품 1위 업체', '', '🎀 정성이 느껴지는 고급스러운 맛\n✨ 유기농 밀가루와 천연 버터 사용\n📞 단체 주문 상담 환영\n▶ 샘플 보기', '', 380000.00, 1900),
(11033, 1, '🥣 아침 대용! 간편 영양죽 7종', '', '✨ 바쁜 아침, 속 편하게 시작하세요\n📌 칼로리는 낮추고 영양은 가득\n💰 1주일 패키지 구매 시 할인\n▶ 신청하기', '', 1670000.00, 8350),
(11034, 1, '🍢 추억의 맛! 부산 어묵 모듬세트', '', '🌊 밀가루 함량 ZERO! 어육 90%\n🔥 뜨끈한 국물용 비법 소스 포함\n🚚 오늘 주문 시 내일 도착\n▶ 구매하기', '', 1060000.00, 5300),
(11035, 1, '🍱 고급 일식 도시락 법인 주문', '', '💼 비즈니스 미팅, 세미나용 격조\n✨ 프리미엄 구성으로 품격 유지\n📞 강남 지역 직접 배송 서비스\n▶ 메뉴 상담', '', 450000.00, 2250),
(11036, 1, '🌽 갓 수확한 초당옥수수 산지직송', '', '🌽 설탕보다 달콤한 아삭한 식감\n🚜 농장에서 바로 따서 보내드려요\n⏰ 단 3일간만 진행하는 한정판매\n▶ 주문하기', '', 1740000.00, 8700),
(11037, 1, '🥪 뚱샌드위치! 속이 꽉 찬 비주얼', '', '🥗 신선한 야채가 아낌없이 듬뿍\n📌 반 쪽만 먹어도 배부른 가성비\n✨ 단체 간식 주문 1순위\n▶ 더 보기', '', 1130000.00, 5650),
(11038, 1, '🦑 쫄깃한 반건조 오징어 특가', '', '🌊 동해바다 해풍으로 말린 명품\n🍺 맥주 안주로 이보다 좋을 수 없다\n💰 10마리 세트 파격 할인가\n▶ 구매하기', '', 520000.00, 2600),
(11039, 1, '🥘 정통 태국 요리 푸팟퐁커리', '', '🇹🇭 태국 현지 셰프의 오리지널 맛\n✨ 부드러운 소프트쉘 크랩의 조화\n📌 평일 점심 할인 혜택 확인\n▶ 예약하기', '', 1810000.00, 9050),
(11040, 1, '🥜 고소함 끝판왕! 수제 견과류 바', '', '✨ 설탕 대신 조청으로 만든 건강간식\n📌 아이들 영양 간식으로 강력 추천\n🎁 선물용 박스 기본 제공\n▶ 확인하기', '', 1200000.00, 6000),
(11041, 1, '🍗 오늘 저녁은 찜닭 어때요?', '', '🔥 매콤한 간장 양념과 당면의 만남\n🧀 치즈 추가로 풍미를 더해보세요\n💰 포장 주문 시 3천원 추가 할인\n▶ 주문하기', '', 590000.00, 2950),
(11042, 1, '🥩 육회 비빔밥 찐맛집의 비결', '', '🐂 당일 도축한 초신선 한우만 사용\n✨ 고소한 참기름 향이 솔솔\n📌 줄 서지 말고 앱으로 미리 주문\n▶ 바로가기', '', 1880000.00, 9400),
(11043, 1, '🥨 독일 정통 프레첼 홈베이킹', '', '🥨 짭짤하고 쫄깃한 마성의 맛\n✨ 냉동 상태로 배송, 굽기만 하면 OK\n💰 10개입 세트 특가 판매 중\n▶ 겟하세요', '', 1270000.00, 6350),
(11044, 1, '🍵 속 편한 전통차와 한과 세트', '', '✨ 정성이 깃든 수제 대추차\n🎁 어르신 명절 선물로 인기 폭발\n📌 보자기 포장 무료 이벤트\n▶ 선물하기', '', 660000.00, 3300),
(11045, 1, '🍲 마라탕 덕후 모여라! 1인 세트', '', '🔥 원하는 재료만 골라 담는 재미\n📌 꿔바로우 미니 사이즈 출시\n💸 리뷰 작성 시 음료수 공짜!\n▶ 주문하기', '', 1950000.00, 9750),
(11046, 1, '🍎 꿀 사과 아침 배송 서비스', '', '🚜 경북 산지에서 직송하는 고당도\n✨ 껍질째 먹는 깨끗한 세척 사과\n💰 정기 구독 시 첫 달 0원\n▶ 신청하기', '', 1340000.00, 6700),
(11047, 1, '🌮 멕시칸 타코 홈파티 키트', '', '🇲🇽 살사 소스부터 나초까지 풀세트\n✨ 친구들과 즐기는 이색 파티 요리\n🔥 30분 내 빠른 배달 서비스\n▶ 주문하기', '', 730000.00, 3650),
(11048, 1, '🐚 통통한 꼬막 비빔밥 맛집', '', '🌊 벌교 꼬막의 쫄깃한 식감\n🍚 밥 한 공기 뚝딱 비우는 마법\n📌 2인분 주문 시 해물파전 반값\n▶ 예약하기', '', 120000.00, 600),
(11049, 1, '🍇 샤인머스캣 역대급 당도 보장', '', '💎 한 알만 먹어도 입안 가득 달콤함\n🚜 농장 직거래로 유통 거품 제거\n✨ 선물용 프리미엄 박스 포장\n▶ 구매하기', '', 1410000.00, 7050),
(11050, 1, '🍣 회전초밥 모든 접시 1,900원', '', '🍱 신선함은 기본, 가성비는 덤\n✨ 셰프가 바로 쥐어주는 수제 초밥\n🔥 주말 대기 시간 확인하고 오세요!\n▶ 위치보기', '', 800000.00, 4000);
