INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11051, 1, '🥩 입안에서 녹는 투뿔 한우 등심', '', '✨ 마블링의 예술, 육즙의 신세계\n🔥 오직 투뿔(1++) 등급만 선별\n📌 오늘 주문 시 구이용 야채 세트 증정\n▶ 지금 주문하기', '', 190000.00, 950),
(11052, 1, '🍲 30년 전통 할매 청국장 밀키트', '', '👵 할머니 손맛 그대로 담았습니다\n✨ 냄새 걱정 없는 특허 받은 비법\n💰 3팩 구매 시 1팩 추가 증정 이벤트\n▶ 맛보러 가기', '', 1480000.00, 7400),
(11053, 1, '🍱 다이어트 도시락 2주 챌린지', '', '🥗 맛있게 먹고 가볍게 비우세요\n✨ 전문 영양사가 설계한 완벽 식단\n🎯 첫 구독 고객 샐러드 1팩 무료\n▶ 식단 확인', '', 870000.00, 4350),
(11054, 1, '☕ 스페셜티 원두 정기 배송', '', '☕ 매주 갓 볶은 신선한 원두를 집에서\n✨ 바리스타가 엄선한 이달의 라인업\n🎁 첫 구독 시 드립백 세트 증정\n▶ 구독 신청', '', 260000.00, 1300),
(11055, 1, '🍤 바삭함의 극치! 수제 왕새우튀김', '', '🌊 깨끗한 기름으로 튀겨낸 황금빛 비주얼\n🔥 맥주 안주로 이보다 좋을 수 없다\n📌 타르타르 소스 대용량 서비스\n▶ 겟하세요', '', 1550000.00, 7750),
(11056, 1, '🥘 스트레스 풀리는 매운 등갈비찜', '', '🔥 맛있게 매운맛의 끝판왕\n✨ 부드러운 살코기가 뼈에서 쏙쏙\n💰 평일 타임세일 전 품목 20% 할인\n▶ 메뉴 보기', '', 940000.00, 4700),
(11057, 1, '🥪 아침의 여유, 프리미엄 샌드위치', '', '🥗 신선한 채소와 수제 소스의 환상 조화\n✨ 단체 주문 및 정기 배송 환영\n📞 지금 문의하면 배달료 0원\n▶ 상담하기', '', 330000.00, 1650),
(11058, 1, '🍎 명품 청송 꿀사과 5kg 초특가', '', '🚜 산지에서 갓 수확해 아삭함이 남달라요\n✨ 당도 선별 완료! 14브릭스 보장\n⚡ 선착순 50박스 한정 수량\n▶ 구매하기', '', 1620000.00, 8100),
(11059, 1, '🥟 속이 꽉 찬 수제 교자 만두', '', '🥟 얇은 피 속 터지는 육즙의 향연\n✨ 굽고, 찌고, 튀겨도 맛있는 만능 만두\n💰 1+1 기획 구성 놓치지 마세요\n▶ 쇼핑하기', '', 1010000.00, 5050),
(11060, 1, '🥤 리얼 과일 착즙 주스 7종', '', '🍓 물 한 방울 섞지 않은 순수 원액\n✨ 아이들 영양 간식으로 최고\n📌 정기배송 신청 시 전용 보냉백 증정\n▶ 더 보기', '', 400000.00, 2000),
(11061, 1, '🍣 집에서 즐기는 홈마카세 세트', '', '🌊 노량진 새벽 시장에서 공수한 횟감\n✨ 손질 완료! 초밥용 밥까지 풀세트\n💎 특별한 날, 홈파티 주인공이 되세요\n▶ 주문하기', '', 1690000.00, 8450),
(11062, 1, '🍜 비 오는 날 생각나는 칼국수', '', '🥢 직접 반죽해 쫄깃한 수제 면발\n🔥 진한 멸치 육수의 깊은 감칠맛\n📌 김치까지 맛있는 찐맛집 밀키트\n▶ 겟하기', '', 1080000.00, 5400),
(11063, 1, '🍩 세상에서 제일 달콤한 수제 도넛', '', '💖 매일 아침 매장에서 직접 굽습니다\n✨ 비주얼 끝판왕, 선물용으로 강추\n🎯 6개입 구매 시 아메리카노 무료\n▶ 구경하기', '', 470000.00, 2350),
(11064, 1, '🍲 보글보글 부대찌개 가성비 세트', '', '🥓 햄 폭탄! 아낌없이 넣었습니다\n✨ 라면 사리 무제한 제공 이벤트\n💰 2인분 가격으로 3인분 즐기기\n▶ 주문하기', '', 1760000.00, 8800),
(11065, 1, '🦐 밥도둑 끝판왕 양념 게장', '', '🔥 매콤달콤 양념에 비벼 먹는 꿀맛\n✨ 비리지 않은 깔끔한 뒷맛 보장\n🚀 오늘 주문하면 내일 밥상 위로!\n▶ 구매하기', '', 1150000.00, 5750),
(11066, 1, '🥐 프랑스 정통 버터 크로와상', '', '🥖 풍미 가득한 고메 버터의 유혹\n✨ 결이 살아있는 바삭한 식감\n💰 마감 세일! 전 품목 30% OFF\n▶ 확인하기', '', 540000.00, 2700),
(11067, 1, '🥩 집에서 굽는 캠핑용 토마호크', '', '🥩 압도적 크기! 육즙 가득 스테이크\n✨ 시즈닝부터 버터까지 모두 포함\n📌 야외 캠핑 필수 준비물 1위\n▶ 준비하기', '', 1830000.00, 9150),
(11068, 1, '🥗 지중해식 샐러드 볼 정기권', '', '🥑 건강한 올리브유와 신선한 토핑\n✨ 몸이 가벼워지는 아침 식단\n💰 한 달 정기 구독 시 20% 할인\n▶ 신청하기', '', 1220000.00, 6100),
(11069, 1, '🥘 추억의 학교 앞 떡볶이 세트', '', '🔥 말랑말랑 밀떡과 매콤 양념의 만남\n✨ 야끼만두와 김말이 서비스 증정\n💰 9,900원의 행복, 지금 클릭\n▶ 주문하기', '', 610000.00, 3050),
(11070, 1, '🥜 하루 한 봉, 프리미엄 견과류', '', '✨ 볶지 않아 영양 그대로 살린 견과\n📌 바쁜 직장인 가방 속 필수템\n🎁 명절 선물용 실속 패키지 출시\n▶ 선물하기', '', 1900000.00, 9500),
(11071, 1, '🍛 일본 현지 맛 그대로! 고체 카레', '', '🇯🇳 진한 풍미의 정통 숙성 카레\n✨ 야채만 넣으면 요리 완성\n💰 신제품 출시 기념 2+1 행사 중\n▶ 쇼핑하기', '', 1290000.00, 6450),
(11072, 1, '🍝 레스토랑 퀄리티 파스타 밀키트', '', '🇮🇹 셰프의 비법 소스를 집에서\n✨ 10분 만에 완성하는 근사한 한 끼\n📌 홈파티, 데이트 메뉴로 강력 추천\n▶ 구경하기', '', 680000.00, 3400),
(11073, 1, '🌽 괴산 대학 찰옥수수 30수 특가', '', '🌽 쫀득쫀득 씹을수록 고소한 맛\n🚜 산지 직송으로 신선하게 배송\n⚡ 수량 한정! 품절 전 서두르세요\n▶ 주문하기', '', 1970000.00, 9850),
(11074, 1, '🍲 뜨끈한 나주 곰탕 한 그릇', '', '✨ 맑고 깊은 국물의 진수를 맛보세요\n🔥 가마솥 방식으로 24시간 우려낸 맛\n📌 수육 한 접시 서비스 이벤트 중\n▶ 맛보기', '', 1360000.00, 6800),
(11075, 1, '🍡 쫄깃쫄깃 굳지 않는 떡 선물세트', '', '💖 개별 포장으로 언제 어디서나 간편하게\n✨ 고소한 콩고물과 꿀떡의 만남\n🎁 답례품 판매 1위 제품 확인\n▶ 선물하기', '', 750000.00, 3750),
(11076, 1, '🥦 유기농 케일 주스 클렌즈 데이', '', '✨ 몸 속 독소를 비우는 3일 프로그램\n🥗 첨가물 없는 순수 채소 착즙액\n💰 챌린지 신청 시 10% 적립금\n▶ 신청하기', '', 140000.00, 700),
(11077, 1, '🥩 제주 흑돼지 오겹살 산지직송', '', '🐷 쫀득한 껍데기와 고소한 비계의 조화\n✨ 멜젓 소스 기본 제공 패키지\n🚀 오늘 잡은 고기 내일 도착!\n▶ 구매하기', '', 1430000.00, 7150),
(11078, 1, '☕ 나만의 홈카페, 콜드브루 원액', '', '❄️ 장시간 추출해 부드러운 목넘김\n✨ 라떼, 아포가토 활용도 만점\n💰 대용량 1L 가성비 끝판왕\n▶ 겟하세요', '', 820000.00, 4100),
(11079, 1, '🥟 장인이 빚은 이북식 손만두', '', '✨ 담백하고 깔끔한 맛이 일품\n🔥 만두전골용 육수 서비스 증정\n📌 어르신들이 더 좋아하시는 그 맛\n▶ 주문하기', '', 210000.00, 1050),
(11080, 1, '🍔 수제 패티가 예술! 인생 버거', '', '🔥 육즙 팡팡 터지는 두툼한 패티\n✨ 직접 구운 번으로 풍미 업그레이드\n💰 배달앱 주문 시 감자튀김 무료\n▶ 주문하기', '', 1500000.00, 7500),
(11081, 1, '🦀 밥 한 그릇 뚝딱! 양념 꼬막장', '', '🌊 벌교 꼬막의 쫄깃한 식감 그대로\n✨ 매콤한 비법 양념장과 환상 조화\n📌 입맛 없을 때 강력 추천 별미\n▶ 더 보기', '', 890000.00, 4450),
(11082, 1, '🥨 독일 정통 수제 프레첼 입고', '', '🥨 고소하고 짭조름한 맥주 도둑\n✨ 시나몬, 초코 등 다양한 라인업\n💰 3개 구매 시 1개 추가 증정\n▶ 구경하기', '', 280000.00, 1400),
(11083, 1, '🥘 집밥 그리울 땐 엄마손 육개장', '', '🔥 얼큰하고 칼칼한 국물 맛\n✨ 건더기가 아낌없이 듬뿍 들어있어요\n📌 1인 가구 추천 간편 조리팩\n▶ 구매하기', '', 1570000.00, 7850),
(11084, 1, '🥖 빵지순례 1순위, 소금빵 세트', '', '✨ 겉은 바삭, 속은 촉촉한 버터 풍미\n🥖 커피와 먹으면 환상의 궁합\n🚀 당일 배송으로 신선하게 받으세요\n▶ 주문하기', '', 960000.00, 4800),
(11085, 1, '🍲 전복 가득! 보양 죽 밀키트', '', '✨ 기력 회복을 위한 든든한 한 끼\n💎 완도산 전복을 아끼지 않았습니다\n💰 신규 가입 시 5천원 할인 쿠폰\n▶ 보러가기', '', 350000.00, 1750),
(11086, 1, '🍹 상큼한 청귤 에이드 원액', '', '🍋 비타민C 가득한 제주 청귤의 맛\n✨ 탄산수만 넣으면 카페 음료 완성\n🎁 2병 구매 시 전용 유리컵 증정\n▶ 구매하기', '', 1640000.00, 8200),
(11087, 1, '🍱 프리미엄 한정식 도시락 배달', '', '💼 중요한 미팅, 귀한 손님 접대용\n✨ 품격 있는 구성과 정성스러운 맛\n📞 전국 단체 주문 배송 가능\n▶ 상담받기', '', 1030000.00, 5150),
(11088, 1, '🥗 단백질 듬뿍! 닭가슴살 샐러드', '', '🐔 퍽퍽하지 않은 수비드 공법 패티\n✨ 한 끼 든든하게 채우는 영양 만점\n💰 정기 배송 신청 시 배송비 면제\n▶ 신청하기', '', 420000.00, 2100),
(11089, 1, '🍲 마라샹궈 집에서 5분 완성', '', '🔥 중독적인 얼얼한 맛의 진수\n✨ 푸주, 분모자 등 인기 재료 풀구성\n📌 지금 사면 미니 꿔바로우 증정\n▶ 겟하기', '', 1710000.00, 8550),
(11090, 1, '🍘 고소한 수제 누룽지 과자', '', '✨ 가마솥에서 구워낸 바삭한 식감\n📌 첨가물 없는 건강한 온가족 간식\n💰 10봉 묶음 구매 시 역대급 특가\n▶ 구매하기', '', 1100000.00, 5500),
(11091, 1, '🍗 야식 1등! 숯불 지코바st 치킨', '', '🔥 불향 가득한 매콤한 양념의 맛\n✨ 치밥하기 딱 좋은 소스 넉넉함\n💰 오늘만 배달팁 0원 이벤트\n▶ 주문하기', '', 490000.00, 2450),
(11092, 1, '🥣 아침 식사 대용 무설탕 요거트', '', '✨ 쫀득한 그릭 요거트의 진수\n🍯 꿀과 그래놀라 토핑 추가 강력 추천\n📌 정기 배송으로 매일 아침 신선하게\n▶ 확인하기', '', 1780000.00, 8900),
(11093, 1, '🥘 정통 안동 찜닭 소스 포함 세트', '', '🔥 집에서도 맛집 맛 그대로 재현\n✨ 당면과 떡 사리가 기본 포함\n💰 마트보다 저렴한 온라인 단독가\n▶ 쇼핑하기', '', 1170000.00, 5850),
(11094, 1, '🍓 설향 딸기 당일 수확 직송', '', '🚜 새벽에 딴 딸기를 점심에 배송\n✨ 압도적인 당도와 풍부한 과즙\n⚡ 신선도 유지를 위해 한정 판매\n▶ 구매하기', '', 560000.00, 2800),
(11095, 1, '🍣 참치 전문점 퀄리티 홈세트', '', '🌊 최고급 북방 참다랑어만 선별\n💎 부위별로 즐기는 참치 파티\n📌 와사비와 간장 세트 포함 배송\n▶ 예약하기', '', 1850000.00, 9250),
(11096, 1, '🥟 김치 손만두의 깔끔한 매운맛', '', '🌶️ 아삭한 김치 식감이 살아있어요\n✨ 구우면 바삭, 끓이면 촉촉한 맛\n💰 3봉 구매 시 무료 배송 찬스\n▶ 담으러 가기', '', 1240000.00, 6200),
(11097, 1, '🍲 해장 끝판왕! 황태 해장국', '', '✨ 속이 풀리는 시원하고 진한 국물\n🔥 10분만 끓이면 전문점 맛 완성\n📌 캠핑장 아침 식사로 인기 만점\n▶ 구매하기', '', 630000.00, 3150),
(11098, 1, '🍝 명란 크림 파스타 밀키트', '', '💎 짭조름한 명란과 고소한 크림의 만남\n✨ 소스가 넉넉해 빵 찍어 먹기 좋아요\n💰 평일 오전 주문 시 당일 발송\n▶ 더 보기', '', 1920000.00, 9600),
(11099, 1, '🥨 크림치즈 가득 수제 프레첼', '', '🥯 입안 가득 퍼지는 부드러운 풍미\n✨ 아이스 아메리카노와 찰떡궁합\n🎯 오늘 사면 2+1 혜택 적용\n▶ 겟하세요', '', 1310000.00, 6550),
(11100, 1, '🍱 건강한 나물 비빔밥 도시락', '', '🌿 산지에서 직송한 신선한 나물 7종\n✨ 비법 고추장으로 감칠맛 업그레이드\n💰 직장인 점심 특가 5,900원\n▶ 주문하기', '', 700000.00, 3500);
