INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11101, 1, '🔥 숯불향 가득! 불막창 1+1 세트', '', '✨ 스트레스 날리는 화끈한 매운맛\n💎 쫄깃한 식감에 베어든 깊은 불향\n📌 지금 주문 시 주먹밥 재료 무료 증정\n▶ 바로 주문하기', '', 1990000.00, 9950),
(11102, 1, '🍰 한 입의 사치, 수제 마카롱 10구', '', '💖 쫀득한 꼬끄와 필링의 환상적인 조화\n✨ 선물하기 딱 좋은 고급 패키지\n💰 오늘만 20% 특별 할인가 적용\n▶ 구경하러 가기', '', 1380000.00, 6900),
(11103, 1, '🍣 초신선! 새벽 배송 모듬회', '', '🌊 오늘 아침 노량진에서 바로 왔습니다\n💎 셰프가 직접 엄선한 제철 생선 구성\n🚀 아침 7시 전 도착 보장 서비스\n▶ 신선 배송 신청', '', 770000.00, 3850),
(11104, 1, '🍜 속이 뻥 뚫리는 명품 짬뽕 밀키트', '', '🔥 전문점 화력을 집에서도 그대로\n✨ 해산물이 아낌없이 듬뿍 들어있어요\n💰 2세트 구매 시 군만두 서비스\n▶ 담으러 가기', '', 160000.00, 800),
(11105, 1, '🥗 아삭아삭 신선한 컵샐러드 5종', '', '🥑 바쁜 아침, 간편하게 채우는 영양\n✨ 매일 아침 직배송으로 신선함 보장\n🎯 정기 구독 시 10% 추가 적립\n▶ 식단 보기', '', 1450000.00, 7250),
(11106, 1, '🥘 정통 태국 맛! 똠양꿍 밀키트', '', '🇹🇭 현지의 맛을 집에서 10분 만에\n✨ 고수부터 레몬그라스까지 완벽 구성\n📌 여행 가고 싶을 때 강력 추천!\n▶ 메뉴 보기', '', 840000.00, 4200),
(11107, 1, '🍗 겉바속촉 끝판왕! 옛날 통닭', '', '✨ 추억의 맛 그대로, 두 마리 만 원대\n🔥 주문 즉시 튀겨 따끈함이 남달라요\n💰 방문 포장 시 콜라 대용량 증정\n▶ 위치 확인', '', 230000.00, 1150),
(11108, 1, '🥤 비타민 듬뿍! ABC 주스 원액', '', '🍎 사과, 비트, 당근의 황금 비율\n✨ 설탕 제로, 원물 100% 착즙\n🎁 신규 가입 시 무료 체험팩 증정\n▶ 체험 신청', '', 1520000.00, 7600),
(11109, 1, '🥘 얼큰한 곱창전골 소주 도둑', '', '🔥 곱이 꽉 찬 프리미엄 소곱창 사용\n✨ 비법 양념장으로 잡내 완벽 제거\n📌 불금 야식 메뉴 고민 끝!\n▶ 주문하기', '', 910000.00, 4550),
(11110, 1, '🥯 뉴욕 스타일 수제 베이글 세트', '', '🥯 겉은 쫄깃 속은 부드러운 정통 맛\n✨ 대용량 크림치즈 3종 기본 제공\n💰 런칭 기념 배송비 0원 혜택\n▶ 쇼핑하기', '', 300000.00, 1500),
(11111, 1, '🍲 엄마가 해준 맛, 소고기 미역국', '', '✨ 한우를 듬뿍 넣어 깊고 진한 국물\n🔥 생일이나 기념일에 딱 좋은 한 끼\n📌 5분 데우기만 하면 식사 끝\n▶ 구매하기', '', 1590000.00, 7950),
(11112, 1, '🍢 길거리 어묵탕 집에서 즐기기', '', '🌊 부산 어묵 명장과 협업한 레시피\n✨ 비법 육수 팩으로 감칠맛 대폭발\n💰 대용량 패키지 파격 특가 중\n▶ 겟하세요', '', 980000.00, 4900),
(11113, 1, '🍛 풍미 가득한 비프 커리 덮밥', '', '🇮🇳 장시간 끓여 깊은 맛이 일품\n✨ 고기 토핑이 아낌없이 듬뿍!\n🎯 직장인 간편 점심으로 강력 추천\n▶ 확인하기', '', 370000.00, 1850),
(11114, 1, '🥨 시나몬 슈가 프레첼 신메뉴', '', '🥨 달콤하고 고소한 풍미의 정점\n✨ 아이들과 함께 즐기기 좋은 간식\n💰 지금 사면 아메리카노 1+1 쿠폰\n▶ 예약하기', '', 1660000.00, 8300),
(11115, 1, '🦞 명품 랍스터 버터구이 세트', '', '🌊 특별한 날, 레스토랑 분위기 완성\n💎 손질된 랍스터와 특제 소스 증정\n🔥 15분 오븐 조리로 완벽한 요리\n▶ 주문하기', '', 1050000.00, 5250),
(11116, 1, '🥟 쫀득한 감자피 잎새 만두', '', '🥟 쫄깃함이 다른 감자 전분 피\n✨ 한 입 크기로 아이들 간식에 최고\n💰 5봉 묶음 구매 시 사은품 증정\n▶ 더 보기', '', 440000.00, 2200),
(11117, 1, '🥦 프리미엄 유기농 채소 박스', '', '🚜 산지에서 직접 엄선한 제철 채소\n✨ 신선도 유지를 위한 친환경 포장\n💰 첫 구독 시 무농약 콩나물 서비스\n▶ 신청하기', '', 1730000.00, 8650),
(11118, 1, '🥘 부드러운 안동 찜닭 홈세트', '', '🔥 넓적 당면이 넉넉하게 들어있어요\n✨ 달콤 짭짤한 마법의 간장 양념\n📌 밥 비벼 먹으면 두 그릇 뚝딱!\n▶ 주문하기', '', 1120000.00, 5600),
(11119, 1, '☕ 디카페인 콜드브루 원액 500ml', '', '✨ 밤에도 걱정 없이 즐기는 진한 커피\n💎 카페인 걱정 없이 풍미는 그대로\n💰 오늘만 1+1 타임 세일 진행\n▶ 구매하기', '', 510000.00, 2550),
(11120, 1, '🥪 아보카도 듬뿍 샌드위치', '', '🥑 숲속의 버터, 신선한 아보카도 사용\n✨ 다이어트 중에도 든든한 한 끼\n🎯 단체 간식 주문 시 로고 스티커 제작\n▶ 문의하기', '', 1800000.00, 9000),
(11121, 1, '🍲 강원도 찰옥수수 범벅 밀키트', '', '🌽 톡톡 터지는 고소함의 극치\n✨ 추억을 부르는 건강한 영양 간식\n📌 부모님 간식 선물로 인기 만점\n▶ 선물하기', '', 1190000.00, 5950),
(11122, 1, '🥩 육질이 다른 이베리코 목살', '', '🐷 세계 4대 진미, 이베리코의 풍미\n✨ 풍부한 육즙과 부드러운 식감\n💰 오늘 주문 시 허브 솔트 증정\n▶ 쇼핑하기', '', 580000.00, 2900),
(11123, 1, '🥣 영양 가득 전복 내장 죽', '', '💎 전복 내장의 고소함이 가득 담긴 맛\n✨ 환자식은 물론 든든한 아침 식사로\n📌 간편하게 데워 드세요\n▶ 확인하기', '', 1870000.00, 9350),
(11124, 1, '🍡 앙금 가득 수제 찹쌀떡 세트', '', '💖 쫄깃함 속에 숨은 달콤한 앙금\n✨ 합격 기원, 답례용으로 완벽\n🎁 고급 보자기로 정성스러운 포장\n▶ 더 보기', '', 1260000.00, 6300),
(11125, 1, '🍕 치즈 폭탄 시카고 피자 특가', '', '🧀 쏟아져 내리는 치즈의 향연\n🔥 오븐이나 에어프라이어 15분 완성\n💰 기간 한정 30% 파격 세일\n▶ 주문하기', '', 650000.00, 3250),
(11126, 1, '🍝 바질 페스토 콜드 파스타', '', '🌿 입안 가득 퍼지는 싱그러운 바질 향\n✨ 입맛 없는 여름철 최고의 별미\n📌 샐러드 대용으로도 훌륭합니다\n▶ 구매하기', '', 1940000.00, 9700),
(11127, 1, '🍲 시원한 바지락 칼국수 2인분', '', '🌊 산지 직송 바지락이 한가득\n✨ 쫄깃한 수제 면발로 맛집 재현\n💰 9,900원의 가성비 행복\n▶ 겟하세요', '', 1330000.00, 6650),
(11128, 1, '🍗 마늘향 가득한 갈릭 치킨', '', '🔥 알싸하고 달콤한 마늘 소스의 비법\n✨ 맥주 안주로 실패 없는 선택\n📌 리뷰 이벤트 참여 시 치즈볼 증정\n▶ 바로가기', '', 720000.00, 3600),
(11129, 1, '🍹 제주 감귤 착즙 에이드 원액', '', '🍊 제주 과수원에서 갓 따온 상큼함\n✨ 탄산수와 섞으면 근사한 홈카페\n💰 2개 사면 배송비 무료 혜택\n▶ 쇼핑하기', '', 110000.00, 550),
(11130, 1, '🍳 에그 베네딕트 브런치 세트', '', '✨ 호텔 조식을 집에서 즐겨보세요\n💎 홀랜다이즈 소스까지 완벽 동봉\n📌 주말 아침 홈파티 메뉴로 추천\n▶ 구경하기', '', 1400000.00, 7000),
(11131, 1, '🥘 매콤달콤 코다리조림 밀키트', '', '🐟 살이 꽉 찬 명품 코다리만 엄선\n✨ 무와 시래기가 듬뿍 들어있어요\n💰 오늘만 5,000원 즉시 할인\n▶ 주문하기', '', 790000.00, 3950),
(11132, 1, '🍩 크림 가득 수제 도넛 6구 세트', '', '💖 매장에서 직접 끓인 커스터드 크림\n✨ 비주얼도 맛도 인생 사진 보장\n🎯 단체 주문 시 추가 할인 혜택\n▶ 메뉴 보기', '', 180000.00, 900),
(11133, 1, '🍲 뜨끈한 소고기 장터 국밥', '', '✨ 고향의 정이 느껴지는 푸짐한 양\n🔥 얼큰한 국물로 속풀이 한 판\n📌 한정 수량 당일 조리 판매 중\n▶ 겟하기', '', 1470000.00, 7350),
(11134, 1, '🥨 벨기에 초코 프레첼 특가전', '', '🍫 진한 다크 초콜릿과 소금의 조화\n✨ 한 번 열면 멈출 수 없는 마성의 맛\n💰 온라인 최저가로 쟁여두세요\n▶ 확인하기', '', 860000.00, 4300),
(11135, 1, '🥩 등심 스테이크 정기 배송 서비스', '', '🥩 매주 전문 등급 소고기만 골라 배송\n✨ 시즈닝과 가니쉬 세트 포함\n💰 첫 달 구독료 50% 할인 혜택\n▶ 신청하기', '', 250000.00, 1250),
(11136, 1, '🥗 단백질 폭탄 훈제 오리 샐러드', '', '🦆 고소한 오리 고기와 신선한 야채\n✨ 포만감 높고 맛있는 다이어트 식단\n📌 수제 오리엔탈 드레싱 증정\n▶ 더 보기', '', 1540000.00, 7700),
(11137, 1, '🍲 마라탕 1인 가구 실속 세트', '', '🔥 혼자서도 푸짐하게 즐기는 마라\n✨ 소고기, 푸주, 납작당면 풀구성\n💰 지금 사면 꿔바로우 미니 서비스\n▶ 주문하기', '', 930000.00, 4650),
(11138, 1, '🍘 전통 가마솥 누룽지 1kg 대용량', '', '✨ 끓여 먹고 구워 먹는 만능 영양 간식\n📌 아침 식사 대용으로 든든합니다\n💰 유통 거품 뺀 직거래 특가\n▶ 구매하기', '', 320000.00, 1600),
(11139, 1, '🍜 해물 가득 쟁반 짜장 2인분', '', '🦐 불맛 가득 볶아낸 정통 중화요리\n✨ 해산물 함량이 압도적입니다\n📌 단 1주일! 무료 배송 이벤트\n▶ 겟하기', '', 1610000.00, 8050),
(11140, 1, '🥣 아침을 깨우는 영양 단호박 죽', '', '🎃 단호박의 단맛을 그대로 살렸어요\n✨ 속 편한 한 끼 식사를 원하신다면\n💰 10팩 구매 시 2팩 증정 찬스\n▶ 쇼핑하기', '', 1000000.00, 5000),
(11141, 1, '🥘 제주 고기 국수 밀키트 출시', '', '🐷 진한 사골 육수와 부드러운 돔베고기\n✨ 제주도의 감동을 집에서 느껴보세요\n📌 선착순 100명 귤 젤리 증정\n▶ 구매하기', '', 390000.00, 1950),
(11142, 1, '🥨 크랜베리 월넛 깜빠뉴 세트', '', '🥖 건강한 통밀로 구운 비건 빵\n✨ 씹을수록 고소하고 담백한 매력\n💰 매일 아침 구워 당일 발송\n▶ 예약하기', '', 1680000.00, 8400),
(11143, 1, '🥩 숯불 돼지갈비 가성비 1kg', '', '🔥 30년 전통 비법 양념에 재웠습니다\n✨ 온 가족이 즐기는 달콤 짭짤한 맛\n💰 마트 가격보다 저렴한 파격 특가\n▶ 주문하기', '', 1070000.00, 5350),
(11144, 1, '🍹 상큼함 충전! 블루베리 원액', '', '🍇 안토시아닌 가득한 슈퍼푸드\n✨ 요거트나 우유에 타 먹기 좋아요\n🎁 선물용 박스 포장 기본 제공\n▶ 확인하기', '', 460000.00, 2300),
(11145, 1, '🍣 고급 일식집 우니(성게알) 입고', '', '🌊 바다의 향긋함을 그대로 담았습니다\n💎 감태와 함께 즐기는 럭셔리 홈파티\n🚀 산지 직송 초신선도 유지 배송\n▶ 주문하기', '', 1750000.00, 8750),
(11146, 1, '🥟 고추 잡채와 꽃빵 세트', '', '✨ 집에서 즐기는 근사한 중식 요리\n🔥 매콤하게 볶아낸 고추 잡채의 풍미\n💰 주말 홈파티 세트 할인 진행\n▶ 더 보기', '', 1140000.00, 5700),
(11147, 1, '🍲 전라도식 진한 추어탕 5팩', '', '✨ 국내산 미꾸라지로 끓인 보양식\n🔥 한입 먹으면 기운이 펄펄!\n📌 부모님 건강 선물로 추천합니다\n▶ 구매하기', '', 530000.00, 2650),
(11148, 1, '🍝 트러플 오일 파스타 밀키트', '', '🍄 세계 3대 진미 트러플의 진한 향\n✨ 셰프의 레시피로 15분 완성\n💰 런칭 기념 특별 할인가 판매 중\n▶ 보러가기', '', 1820000.00, 9100),
(11149, 1, '🥨 바삭바삭 수제 츄러스 세트', '', '✨ 놀이공원 그 맛! 집에서 간편하게\n🍫 초코 디핑 소스 기본 포함 구성\n💰 아이들 간식 인기 순위 1위\n▶ 겟하세요', '', 1210000.00, 6050),
(11150, 1, '🍱 간편하고 맛있는 유부초밥 팩', '', '🍱 피크닉 필수템, 10분 뚝딱 완성\n✨ 토핑에 따라 달라지는 다양한 맛\n💰 마감 직전 반값 타임 세일!\n▶ 주문하기', '', 600000.00, 3000);
