INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11201, 1, '🔥 스트레스 킬러! 매운 실비김치', '', '✨ 맵부심 자극하는 화끈한 감칠맛\n💎 짜장라면, 수육과 찰떡궁합 보장\n📌 당일 버무려 신선하게 배송됩니다\n▶ 도전하기', '', 1790000.00, 8950),
(11202, 1, '🍰 꾸덕함의 끝판왕! 황치즈 버터바', '', '🧀 진한 체다 치즈의 풍미가 입안 가득\n✨ 얼려 먹으면 더 맛있는 디저트\n💰 5개 구매 시 1개 추가 증정\n▶ 구매하기', '', 1180000.00, 5900),
(11203, 1, '🍣 탱글탱글! 독도 꽃새우 회', '', '🌊 산지 직송으로 즐기는 달큰한 맛\n💎 귀한 분을 위한 최고의 안주\n🚀 산소 포장으로 살아있는 신선함 배송\n▶ 주문하기', '', 570000.00, 2850),
(11204, 1, '🍜 불향 가득! 차돌 짬뽕 밀키트', '', '🔥 고소한 차돌박이와 얼큰한 국물의 만남\n✨ 야채를 직화로 볶아 풍미를 살렸습니다\n💰 2인분 세트 파격 할인가 판매 중\n▶ 겟하세요', '', 1860000.00, 9300),
(11205, 1, '🥗 두부면 샐러드 파스타', '', '🥑 칼로리 걱정 없는 건강한 면 요리\n✨ 오리엔탈 드레싱으로 깔끔한 맛\n🎯 다이어터 식단 1위 제품 확인\n▶ 식단 보기', '', 1250000.00, 6250),
(11206, 1, '🥘 정통 인도식 치킨 마살라 커리', '', '🇮🇳 현지 향신료로 살린 깊고 진한 맛\n✨ 화덕에 구운 난(Nan) 2장 서비스\n📌 이국적인 맛이 그리울 때 추천\n▶ 메뉴 보기', '', 640000.00, 3200),
(11207, 1, '🍗 마늘 치킨의 성지! 의성 마늘 통닭', '', '✨ 의성 마늘을 듬뿍 다져 넣은 알싸함\n🔥 겉은 바삭하고 속은 촉촉한 마법의 맛\n💰 평일 배달료 무료 이벤트 진행\n▶ 주문하기', '', 1930000.00, 9650),
(11208, 1, '🥤 리얼 망고 착즙 주스 1L', '', '🥭 망고 과육 100%의 진한 달콤함\n✨ 아이들 건강 간식으로 이보다 좋을 수 없다\n🎁 3병 세트 구매 시 전용 보틀 증정\n▶ 구매하기', '', 1320000.00, 6600),
(11209, 1, '🥘 속이 꽉 찬 프리미엄 곱창볶음', '', '🔥 잡내 없이 깔끔하게 매운 비법 양념\n✨ 당면과 깻잎이 듬뿍 들어있어요\n📌 야식 메뉴 고민될 땐 무조건 클릭\n▶ 주문하기', '', 710000.00, 3550),
(11210, 1, '🥯 소금빵 베이글의 환상적 만남', '', '🥯 짭조름한 소금과 고소한 버터 풍미\n✨ 에어프라이어 3분이면 갓 구운 맛\n💰 마감 세일! 4개 묶음 30% OFF\n▶ 쇼핑하기', '', 100000.00, 500),
(11211, 1, '🍲 할머니 손맛 고기 듬뿍 김치찌개', '', '✨ 푹 익은 묵은지와 돼지 앞다리살의 조화\n🔥 밥 두 그릇 뚝딱 비우는 인생 찌개\n📌 10분 완성 간편 밀키트 구성\n▶ 구매하기', '', 1390000.00, 6950),
(11212, 1, '🍢 부산 명물! 물떡과 어묵 세트', '', '🌊 쫀득한 가래떡과 비법 육수의 만남\n✨ 겨울철 추위를 녹여줄 따끈한 국물\n💰 캠핑용 대용량 패키지 출시 특가\n▶ 겟하세요', '', 780000.00, 3900),
(11213, 1, ' Curry 마스터의 일본식 카레 돈까스', '', '🇯🇵 저온 숙성으로 부드러운 돈까스 육질\n✨ 진한 카레 소스와의 완벽한 밸런스\n🎯 직장인 점심 배달 인기 순위 상위권\n▶ 확인하기', '', 170000.00, 850),
(11214, 1, '🥨 바삭바삭 시나몬 프레첼 츄러스', '', '🥨 놀이공원에서 먹던 그 추억의 맛\n✨ 초코 디핑 소스에 콕 찍어 드세요\n💰 주말 한정 1+1 득템 찬스\n▶ 예약하기', '', 1460000.00, 7300),
(11215, 1, '🦞 명품 영덕 대게 3마리 실속 세트', '', '🌊 수율 90% 이상! 꽉 찬 속살을 확인하세요\n💎 대게딱지장 비빔밥용 내장 포함\n🔥 산지 직송으로 가장 신선하게 배송\n▶ 주문하기', '', 850000.00, 4250),
(11216, 1, ' dumpling의 진수! 수제 새우 굴림만두', '', '🥟 만두피가 거의 없는 꽉 찬 소의 맛\n✨ 통새우가 톡톡 터지는 식감이 일품\n💰 500g 대용량 지퍼백 포장\n▶ 더 보기', '', 240000.00, 1200),
(11217, 1, '🥦 새벽 수확! 무농약 방울토마토 3kg', '', '🚜 탱글탱글 터지는 과즙의 싱그러움\n✨ 스테비아 토마토보다 더 건강한 단맛\n💰 농장 직거래로 유통 거품을 뺐습니다\n▶ 신청하기', '', 1530000.00, 7650),
(11218, 1, '🥘 매콤 짭짤! 춘천 철판 닭갈비', '', '🔥 국내산 신선육으로 만든 부드러운 맛\n✨ 우동 사리와 고구마 토핑 기본 제공\n📌 볶음밥까지 완벽한 한 끼 완성\n▶ 주문하기', '', 920000.00, 4600),
(11219, 1, '☕ 에티오피아 예가체프 드립백 20개', '', '✨ 화사한 꽃향기와 기분 좋은 산미\n💎 사무실에서도 즐기는 고급 원두 커피\n💰 런칭 기념 특별 할인가 적용 중\n▶ 구매하기', '', 310000.00, 1550),
(11220, 1, '🥪 속이 꽉 찬 에그 마요 샌드위치', '', '🥚 부드러운 달걀과 고소한 마요네즈\n✨ 아이들 영양 간식으로 인기 폭발\n🎯 단체 도시락 예약 시 배달료 면제\n▶ 문의하기', '', 1600000.00, 8000),
(11221, 1, '🍲 담백하고 시원한 북어국 밀키트', '', '✨ 술 마신 다음 날, 속 풀이 1등 메뉴\n🔥 참기름에 달달 볶아 고소함이 두 배\n📌 바쁜 아침 5분이면 충분합니다\n▶ 선물하기', '', 990000.00, 4950),
(11222, 1, '🥩 육즙 가득! 프리미엄 양갈비(숄더랙)', '', '🐑 잡내 제로! 어린 양만 엄선했습니다\n✨ 캠핑장 분위기를 업그레이드할 비주얼\n💰 오늘만 쯔란 소스 대용량 증정\n▶ 쇼핑하기', '', 380000.00, 1900),
(11223, 1, '🥣 보양의 정석! 닭 한 마리 칼국수', '', '💎 푹 고아낸 닭 육수와 부드러운 살코기\n✨ 마지막 칼국수 사리까지 든든하게\n📌 가족 외식 메뉴로 강력 추천\n▶ 확인하기', '', 1670000.00, 8350),
(11224, 1, '🍡 말랑말랑 수제 꿀떡 1kg', '', '💖 입안에서 꿀이 톡! 터지는 달콤함\n✨ 굳지 않는 특허 공법으로 더 쫄깃하게\n🎁 답례품 판매 1위, 정성껏 담았습니다\n▶ 더 보기', '', 1060000.00, 5300),
(11225, 1, '🍕 치즈 덕후 모여라! 콰트로 포르마지', '', '🧀 4가지 프리미엄 치즈의 진한 하모니\n🔥 화덕에서 구운 담백한 도우의 맛\n💰 방문 포장 시 오븐 스파게티 서비스\n▶ 주문하기', '', 450000.00, 2250),
(11226, 1, '🍝 트러플 향 가득! 버섯 크림 파스타', '', '🍄 고급스러운 트러플의 풍미를 집에서\n✨ 우유와 생크림으로 낸 진한 소스 맛\n📌 홈파티, 기념일 메뉴로 완벽\n▶ 구매하기', '', 1740000.00, 8700),
(11227, 1, '🍲 통통한 낙지 전골 2인분', '', '🌊 쓰러진 소도 일으킨다는 영양 만점 낙지\n✨ 미나리와 버섯으로 시원한 국물 맛\n💰 지금 사면 라면 사리 무제한 공짜\n▶ 겟하세요', '', 1130000.00, 5650),
(11228, 1, '🍗 바삭함의 혁명! 쌀가루 치킨', '', '🔥 쌀가루로 튀겨 더 고소하고 바삭해요\n✨ 소화가 잘 되어 야식으로 먹어도 안심\n📌 리뷰 작성 시 치즈 시즈닝 증정\n▶ 바로가기', '', 520000.00, 2600),
(11229, 1, '🍹 상큼함 폭발! 자두 에이드 원액', '', '🍑 여름 자두의 달콤 상큼한 맛 그대로\n✨ 홈메이드 에이드, 요거트 토핑으로 활용\n💰 2병 세트 구매 시 전용 텀블러 증정\n▶ 쇼핑하기', '', 1810000.00, 9050),
(11230, 1, '🍳 폭신한 수플레 팬케이크 세트', '', '✨ 입에서 살살 녹는 구름 같은 식감\n💎 휘핑크림과 메이플 시럽 풀패키지\n📌 주말 브런치로 럭셔리하게 즐기세요\n▶ 구경하기', '', 1200000.00, 6000),
(11231, 1, '🥘 매콤 아삭! 코다리 조림 3인분', '', '🐟 살이 꽉 찬 명품 코다리와 시래기\n✨ 양념에 밥 비벼 먹으면 밥도둑 확정\n💰 오늘만 5,000원 즉시 할인 혜택\n▶ 주문하기', '', 590000.00, 2950),
(11232, 1, '🍩 크림 치즈 가득! 수제 도넛', '', '💖 꾸덕한 크림 치즈가 빈틈없이 꽉!\n✨ 커피와 함께라면 여기가 바로 디저트 맛집\n🎯 어린이 간식 및 단체 배달 환영\n▶ 메뉴 보기', '', 1880000.00, 9400),
(11233, 1, '🍲 진한 사골 육수의 고기 국밥', '', '✨ 잡내 없이 깔끔하게 우려낸 뽀얀 국물\n🔥 고기가 아낌없이 듬뿍 들어있습니다\n📌 해장과 보양을 동시에 잡으세요\n▶ 겟하기', '', 1270000.00, 6350),
(11234, 1, '🥨 단짠의 정석! 솔티드 카라멜 프레첼', '', '🥨 수제 카라멜 소스의 깊은 풍미\n✨ 한 번 먹으면 멈출 수 없는 중독성\n💰 온라인 단독! 3+1 증정 행사 중\n▶ 확인하기', '', 660000.00, 3300),
(11235, 1, '🥩 투뿔 한우 불고기 정기 배송', '', '🥩 1++ 등급 한우로 만든 명품 불고기\n✨ 자극적이지 않은 건강한 비법 양념\n💰 구독 첫 달 반값 할인 이벤트\n▶ 신청하기', '', 1950000.00, 9750),
(11236, 1, '🥗 단백질 가득! 훈제 오리 샐러드', '', '🦆 고소한 훈제 오리와 신선한 야채의 만남\n✨ 머스타드 드레싱으로 깔끔하게 마무리\n📌 식단 관리 중에도 든든한 한 끼\n▶ 더 보기', '', 1340000.00, 6700),
(11237, 1, '🍲 마라샹궈 집에서 5분 완성 세트', '', '🔥 얼얼한 중독성! 마라 매니아 필수템\n✨ 소고기, 분모자, 푸주까지 완벽 구성\n💰 지금 주문 시 칭따오 무알콜 증정\n▶ 주문하기', '', 730000.00, 3650),
(11238, 1, '🍘 가마솥에 구운 현미 누룽지 1kg', '', '✨ 국내산 현미 100%로 만든 건강 간식\n📌 바삭바삭하고 고소해 아이들도 좋아해요\n💰 공장 직판가로 저렴하게 쟁여두세요\n▶ 구매하기', '', 120000.00, 600),
(11239, 1, '🍜 정통 일본식 소유 라멘 밀키트', '', '🥢 깔끔한 간장 육수와 쫄깃한 생면\n✨ 차슈 토핑이 들어있어 전문점 퀄리티\n📌 15분 만에 완성하는 일본 여행의 맛\n▶ 겟하기', '', 1410000.00, 7050),
(11240, 1, '🥣 달큰하고 부드러운 단호박죽 7팩', '', '🎃 단호박 원물 그대로의 진한 풍미\n✨ 아침 대용으로 속 편하고 든든하게\n💰 1주일 패키지 구매 시 무료 배송\n▶ 쇼핑하기', '', 800000.00, 4000),
(11241, 1, '🥘 밥 비벼 먹는 차돌 된장 짜글이', '', '🥩 차돌박이가 듬뿍 들어가 고소한 맛\n✨ 밥 위에 슥슥 비벼 먹으면 꿀맛 보장\n📌 자취생 강력 추천 간편 조리팩\n▶ 구매하기', '', 190000.00, 950),
(11242, 1, '🥨 건강한 통밀 깜빠뉴 3종 세트', '', '🥖 무설탕, 무버터! 다이어트 건강 빵\n✨ 씹을수록 구수한 통밀 본연의 매력\n💰 매일 아침 구워 신선하게 발송\n▶ 예약하기', '', 1480000.00, 7400),
(11243, 1, '🥩 야외 캠핑용 돼지 등갈비 1kg', '', '🔥 숯불에 구우면 더 맛있는 양념 등갈비\n✨ 뜯어 먹는 재미가 쏠쏠한 캠핑 메뉴\n💰 오늘 주문 시 마늘 시즈닝 증정\n▶ 주문하기', '', 870000.00, 4350),
(11244, 1, '🍹 비타민C 충전! 레몬 착즙 원액', '', '🍋 물 한 방울 안 섞인 100% 레몬즙\n✨ 레몬에이드, 하이볼 베이스로 활용도 만점\n🎁 전용 휴대용 계량컵 기본 제공\n▶ 확인하기', '', 260000.00, 1300),
(11245, 1, '🍣 입에서 녹는 연어 뱃살 필렛 500g', '', '🌊 초신선 슈페리어 등급 생연어만 사용\n💎 두툼하게 썰어 즐기는 연어회의 정석\n🚀 아이스박스 풀패킹 신선도 유지\n▶ 주문하기', '', 1550000.00, 7750),
(11246, 1, ' dumpling의 화려한 변신! 비빔 만두', '', '🥟 바삭하게 튀긴 만두와 매콤 야채무침\n✨ 술안주로도, 야식으로도 최고의 선택\n💰 만두 3봉 구매 시 비법 소스 증정\n▶ 담으러 가기', '', 940000.00, 4700),
(11247, 1, '🍲 원기 회복! 전복 삼계탕 밀키트', '', '✨ 통전복이 들어간 프리미엄 보양식\n🔥 가마솥 방식으로 우려낸 진한 국물\n📌 부모님 기력 회복 선물로 추천\n▶ 구매하기', '', 330000.00, 1650),
(11248, 1, '🍝 바다 향 가득! 봉골레 파스타', '', '🐚 신선한 바지락과 화이트 와인의 풍미\n✨ 셰프의 레시피로 10분 만에 완성\n💰 기간 한정 20% 특별 세일 진행\n▶ 보러가기', '', 1620000.00, 8100),
(11249, 1, '🥨 벨기에 초코 가득 츄러스 프레첼', '', '🍫 진한 다크 초콜릿의 달콤 쌉싸름함\n✨ 간식 시간의 주인공이 되어보세요\n🎯 선착순 100명 1+1 이벤트\n▶ 겟하세요', '', 1010000.00, 5050),
(11250, 1, '🍱 정갈한 9첩 반상 도시락', '', '🍱 매일 신선한 재료로 정성을 다했습니다\n✨ 한식 전문가가 직접 구성한 균형 잡힌 식단\n💰 직장인 월 결제 시 포인트 10% 적립\n▶ 주문하기', '', 400000.00, 2000);
