INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11251, 1, '🔥 육즙이 팡팡! 수제 가라아게', '', '✨ 닭다리살만 사용해 차원이 다른 부드러움\n🔥 에어프라이어 10분이면 이자카야 완성\n💰 맥주 4캔 만원 행사와 함께 즐기세요\n▶ 담으러 가기', '', 1690000.00, 8450),
(11252, 1, '🍰 입에서 살살 녹는 티라미수', '', '💖 이탈리아 정통 레시피로 만든 부드러움\n✨ 마스카포네 치즈의 깊은 풍미를 느껴보세요\n💰 2개 이상 구매 시 15% 즉시 할인\n▶ 달콤함 충전', '', 1080000.00, 5400),
(11253, 1, '🍣 입안 가득 바다향! 성게알(우니)', '', '🌊 초신선 북해도산 우니 단독 입고\n💎 크리미한 식감과 달큰한 뒷맛의 조화\n🚀 오늘 오후 4시 전 주문 시 내일 새벽 도착\n▶ 신선 배송 신청', '', 470000.00, 2350),
(11254, 1, '🍜 명인 비법! 멸치 국수 밀키트', '', '🥢 진하게 우려낸 육수와 쫄깃한 소면\n✨ 5분 만에 완성하는 시장 칼국수 그 맛\n💰 가성비 끝판왕! 4인분 세트 특가\n▶ 겟하세요', '', 1760000.00, 8800),
(11255, 1, '🥗 단백질 듬뿍! 연어 스테이크 샐러드', '', '🥑 오메가3 가득한 생연어와 신선한 루꼴라\n✨ 다이어트 식단도 맛있게 즐기세요\n🎯 정기 구독 시 수제 드레싱 3종 증정\n▶ 식단 보기', '', 1150000.00, 5750),
(11256, 1, '🥘 베트남 현지 손맛! 소고기 쌀국수', '', '🇻🇳 12시간 우려낸 깊고 진한 육수\n✨ 고수와 레몬, 숙주까지 신선 패키지\n📌 비 오는 날 생각나는 따뜻한 한 끼\n▶ 메뉴 보기', '', 540000.00, 2700),
(11257, 1, '🔥 야식의 제왕! 직화 불닭발', '', '✨ 스트레스 타파! 맛있게 매운 직화의 맛\n💎 쫀득한 콜라겐 덩어리, 무뼈로 편하게\n📌 지금 주문하면 부드러운 계란찜 서비스\n▶ 야식 주문하기', '', 1830000.00, 9150),
(11258, 1, '🥤 100% 석류 착즙 원액 1L', '', '🍎 첨가물 제로! 에스트로겐 가득한 건강 주스\n✨ 매일 아침 한 잔으로 생기를 채우세요\n🎁 선물용 프리미엄 유리병 포장 가능\n▶ 구매하기', '', 1220000.00, 6100),
(11259, 1, '🥘 곱창 가득! 얼큰 소곱창 전골', '', '🔥 곱이 꽉 찬 프리미엄 곱창만 엄선\n✨ 야채와 당면 사리 기본 포함 구성\n📌 불금 홈파티 안주로 강력 추천!\n▶ 주문하기', '', 610000.00, 3050),
(11260, 1, '🥯 갓 구운 쪽파 크림치즈 베이글', '', '🥯 SNS 화제의 그 베이글! 드디어 출시\n✨ 쫀득한 베이글과 알싸한 쪽파의 만남\n💰 신제품 출시 기념 1+1 이벤트\n▶ 쇼핑하기', '', 1900000.00, 9500),
(11261, 1, '🍲 속이 편안한 황태 계란국', '', '✨ 해장으로 최고! 담백하고 시원한 국물\n🔥 바쁜 아침 3분 만에 준비하는 든든함\n📌 저염 식단으로 아이들도 안심하고 먹어요\n▶ 구매하기', '', 1290000.00, 6450),
(11262, 1, '🍢 프리미엄 수제 모둠 어묵 세트', '', '🌊 생선 함량 90% 이상의 탱글한 식감\n✨ 어묵탕, 볶음, 간식으로 다양하게 활용\n💰 오늘만 대용량 패키지 30% 세일\n▶ 겟하세요', '', 680000.00, 3400),
(11263, 1, '🍛 매콤 짭짤! 태국식 돼지고기 덮밥', '', '🇹🇭 팟카파오무쌉의 맛을 집에서 그대로\n✨ 계란 후라이 하나만 올리면 요리 완성\n🎯 바쁜 직장인 점심 메뉴 고민 끝\n▶ 확인하기', '', 1970000.00, 9850),
(11264, 1, '🥨 달콤 바삭! 아몬드 프레첼', '', '🥨 고소한 아몬드 토핑이 듬뿍 뿌려진 별미\n✨ 시네마 데이트 기분을 집에서 즐기세요\n💰 3개 구매 시 아메리카노 1잔 무료\n▶ 예약하기', '', 1360000.00, 6800),
(11265, 1, '🦞 버터향 솔솔~ 킹크랩 다리살', '', '🌊 귀한 킹크랩을 먹기 좋게 손질 완료\n💎 특별한 날, 홈스토랑 주인공이 되세요\n🔥 단 48시간! 역대급 최저가 도전\n▶ 주문하기', '', 750000.00, 3750),
(11266, 1, '🥟 육즙 가득! 프리미엄 샤오롱바오', '', '🥟 얇은 피 속 터지는 진한 육즙의 감동\n✨ 찜기에 7분이면 딤섬 맛집 완성\n💰 5봉 세트 구매 시 전용 찜기 증정\n▶ 더 보기', '', 140000.00, 700),
(11267, 1, '🥦 산지직송! 무농약 파프리카 2kg', '', '🚜 밭에서 갓 따온 아삭아삭한 신선함\n✨ 알록달록 색감으로 샐러드에 활력을\n💰 유통 마진 뺀 정직한 농부의 가격\n▶ 신청하기', '', 1430000.00, 7150),
(11268, 1, '🥘 간장 베이스! 안동 찜닭 밀키트', '', '🔥 넓적 당면과 감자가 듬뿍 들어있어요\n✨ 짜지 않고 감칠맛 도는 비법 양념\n📌 밥 두 그릇 예약! 온 가족 저녁 메뉴\n▶ 주문하기', '', 820000.00, 4100),
(11269, 1, '☕ 과테말라 안티구아 원두 500g', '', '✨ 스모키한 향과 깊은 바디감의 정수\n💎 홈바리스타를 위한 신선한 당일 로스팅\n💰 첫 구매 고객 샘플 원두 증정\n▶ 구매하기', '', 210000.00, 1050),
(11270, 1, '🥪 클럽 샌드위치의 정석 2입 세트', '', '🥗 햄, 치즈, 신선 야채가 3단으로 가득\n✨ 피크닉 갈 때 챙기기 좋은 깔끔 포장\n🎯 단체 주문 시 10% 추가 할인 혜택\n▶ 문의하기', '', 1500000.00, 7500),
(11271, 1, '🍲 강원도 명물! 옹심이 칼국수', '', '🌽 감자의 쫀득함이 살아있는 옹심이\n✨ 구수하고 진한 들깨 국물의 조화\n📌 부모님이 극찬하신 바로 그 맛!\n▶ 선물하기', '', 890000.00, 4450),
(11272, 1, '🥩 육즙 가득! 프리미엄 돈마호크', '', '🐷 겉바속촉 스테이크의 끝판왕\n✨ 캠핑장 비주얼 담당, 맛도 압도적\n💰 오늘 주문 시 시즈닝 가루 증정\n▶ 쇼핑하기', '', 280000.00, 1400),
(11273, 1, '🥣 고소한 영양 가득 잣죽 5팩', '', '💎 가평 특산물 잣을 아낌없이 넣었습니다\n✨ 부드럽고 고소해 아침 대용으로 최고\n📌 소화가 잘 되어 환자 보양식으로 강추\n▶ 확인하기', '', 1570000.00, 7850),
(11274, 1, '🍡 쫄깃쫄깃 수제 인절미 세트', '', '💖 콩고물이 듬뿍! 고소함의 결정체\n✨ 당일 제조, 당일 배송 원칙 엄수\n🎁 명절 선물용 실크 보자기 포장 서비스\n▶ 더 보기', '', 960000.00, 4800),
(11275, 1, '🍕 페퍼로니 가득! 정통 뉴욕 피자', '', '🧀 짭짤한 페퍼로니가 빈틈없이 꽉!\n🔥 집에서 즐기는 갓 구운 피자의 맛\n💰 주말 한정 방문 포장 50% 할인\n▶ 주문하기', '', 350000.00, 1750),
(11276, 1, '🍝 명란 가득! 들기름 파스타 밀키트', '', '🌿 짭조름한 명란과 고소한 들기름의 만남\n✨ 10분 만에 완성하는 퓨전 이탈리안\n📌 입맛 없는 날 별미로 최고입니다\n▶ 구매하기', '', 1640000.00, 8200),
(11277, 1, '🍲 통통한 바지락 술찜 2인분', '', '🌊 해캄 완료! 신선한 바지락이 한가득\n✨ 화이트 와인의 풍미로 근사한 안주 완성\n💰 12,900원의 고품격 홈바 메뉴\n▶ 겟하세요', '', 1030000.00, 5150),
(11278, 1, '🍗 알싸한 매력! 와사비 마요 치킨', '', '🔥 코끝 찡한 와사비와 부드러운 마요네즈\n✨ 느끼함 싹 잡은 중독성 강한 맛\n📌 리뷰 작성 시 감자튀김 서비스 증정\n▶ 바로가기', '', 420000.00, 2100),
(11279, 1, '🍹 상큼 달콤! 샤인머스캣 에이드', '', '🍇 귀한 샤인머스캣의 맛을 그대로 담았다\n✨ 탄산수만 넣으면 에이드 전문점 완성\n💰 2병 구매 시 전용 텀블러 증정\n▶ 쇼핑하기', '', 1710000.00, 8550),
(11280, 1, '🍳 정통 프렌치 토스트 세트', '', '✨ 계란물 듬뿍! 폭신폭신한 식감\n💎 메이플 시럽과 슈가 파우더 기본 포함\n📌 브런치 카페 부럽지 않은 주말 아침\n▶ 구경하기', '', 1100000.00, 5500),
(11281, 1, '🥘 매콤 아삭! 콩나물 불고기', '', '🔥 콩불 맛집 레시피 그대로 담았습니다\n✨ 볶음밥용 김가루와 참기름 서비스\n💰 오늘만 3,000원 선착순 쿠폰 발급\n▶ 주문하기', '', 490000.00, 2450),
(11282, 1, '🍩 다크 초코 가득! 수제 도넛', '', '💖 진한 벨기에산 초콜릿의 깊은 풍미\n✨ 당 충전이 필요한 오후의 필수템\n🎯 어린이집/학교 단체 간식 주문 폭주\n▶ 메뉴 보기', '', 1780000.00, 8900),
(11283, 1, '🍲 얼큰 시원! 버섯 매운탕 칼국수', '', '✨ 버섯과 미나리가 듬뿍! 국물 맛 예술\n🔥 마지막 죽 재료까지 포함된 알찬 구성\n📌 캠핑장 아침 해장용으로 1순위\n▶ 겟하기', '', 1170000.00, 5850),
(11284, 1, '🥨 시나몬 슈가 가득! 수제 프레첼', '', '🍫 시나몬 향이 코끝을 자극하는 달콤함\n✨ 영화 볼 때 하나씩 집어 먹기 좋아요\n💰 온라인 단독! 5개 묶음 20% 할인\n▶ 확인하기', '', 560000.00, 2800),
(11285, 1, '🥩 한우 채끝 스테이크 정기 배송', '', '🥩 1등급 한우만 엄선해 문 앞까지 배달\n✨ 매주 달라지는 셰프의 가니쉬 구성\n💰 첫 달 구독 시 스테이크 전용 팬 증정\n▶ 신청하기', '', 1850000.00, 9250),
(11286, 1, '🥗 리코타 치즈 가득! 계절 과일 샐러드', '', '🧀 꾸덕한 수제 리코타 치즈가 두 스쿱\n✨ 신선한 딸기/포도와 발사믹의 조화\n📌 건강한 한 끼 식사로 충분합니다\n▶ 더 보기', '', 1240000.00, 6200),
(11287, 1, '🍲 마라탕 매니아를 위한 소고기 세트', '', '🔥 얼얼한 마라향에 소고기 추가는 국룰\n✨ 푸주, 건두부, 옥수수면 풀패키지\n💰 지금 주문하면 칭따오 무알콜 증정\n▶ 주문하기', '', 630000.00, 3150),
(11288, 1, '🍘 고소한 보리 누룽지 2kg', '', '✨ 국내산 보리로 만들어 더 구수한 맛\n📌 과자 대신 먹기 좋은 건강 간식\n💰 도매가 수준의 파격적인 대용량 특가\n▶ 구매하기', '', 1920000.00, 9600),
(11289, 1, '🍜 Ramen의 정석! 돈코츠 라멘 밀키트', '', '🍜 차슈와 아지타마고까지 들어있는 정성\n✨ 뽀얀 사골 육수의 진한 풍미를 느끼세요\n📌 줄 서서 먹는 맛집의 맛 100% 재현\n▶ 겟하기', '', 1310000.00, 6550),
(11290, 1, '🥣 영양 만점! 팥죽과 새알심 7팩', '', '✨ 팥의 진한 맛과 쫀득한 새알심의 만남\n💎 동지날은 물론 평소 간식으로도 최고\n💰 1주일 패키지 구매 시 무료 배송\n▶ 쇼핑하기', '', 700000.00, 3500),
(11291, 1, '🥘 밥도둑! 묵은지 고등어 조림', '', '🐟 잘 익은 묵은지와 통통한 고등어의 조화\n✨ 엄마 손맛 그리울 때 생각나는 메뉴\n📌 15분만 끓여서 갓 지은 밥과 드세요\n▶ 구매하기', '', 1990000.00, 9950),
(11292, 1, '🥨 정통 호밀 깜빠뉴 3종 세트', '', '🥖 건강을 생각한 천연 발효종 무설탕 빵\n✨ 씹을수록 담백한 호밀의 매력\n💰 매일 아침 구워 신선하게 당일 발송\n▶ 예약하기', '', 1380000.00, 6900),
(11293, 1, '🥩 숯불향 돼지 양념 구이 2kg', '', '🔥 특제 소스에 48시간 숙성한 부드러움\n✨ 아이들도 잘 먹는 단짠단짠의 정석\n💰 캠핑/여행용 대용량 가성비 끝판왕\n▶ 주문하기', '', 770000.00, 3850),
(11294, 1, '🍹 비타민 충전! 깔라만시 원액', '', '🍋 기름진 음식 먹은 후 상큼하게 한 잔\n✨ 다이어트 중 물 대신 마시기 좋아요\n🎁 전용 휴대용 보틀 기본 제공\n▶ 확인하기', '', 160000.00, 800),
(11295, 1, '🍣 집에서 즐기는 참다랑어 대뱃살', '', '🌊 입에서 살살 녹는 최고급 오도로\n💎 전문점 가격의 절반으로 즐기는 사치\n🚀 초저온 냉동 포장으로 선도 완벽 유지\n▶ 주문하기', '', 1450000.00, 7250),
(11296, 1, '🥟 부추 가득! 담백한 물만두', '', '🥟 부추의 향긋함과 돼지고기의 고소함\n✨ 끓는 물에 3분이면 완성되는 간편함\n💰 3봉 구매 시 군만두 1봉 추가 증정\n▶ 담으러 가기', '', 840000.00, 4200),
(11297, 1, '🍲 24시간 가마솥 사골 곰탕', '', '✨ 첨가물 없이 뼈만 고아낸 진짜 진국\n🔥 떡국, 만둣국 베이스 육수로 만능 활용\n📌 부모님 건강 식단으로 강력 추천\n▶ 구매하기', '', 230000.00, 1150),
(11298, 1, '🍝 쉬림프 알리오올리오 밀키트', '', '🦐 통통한 칵테일 새우가 듬뿍 들어있어요\n✨ 마늘 향 가득한 오일 소스의 감칠맛\n💰 런칭 기념 기간 한정 30% 할인\n▶ 보러가기', '', 1520000.00, 7600),
(11299, 1, '🥨 시나몬 롤 프레첼 신제품', '', '🥯 시나몬의 향긋함과 아이싱의 달콤함\n✨ 당 충전이 필요한 오후 3시의 간식\n🎯 오늘 주문 시 2+1 자동 적용\n▶ 겟하세요', '', 910000.00, 4550),
(11300, 1, '🍱 정갈한 12첩 반찬 도시락', '', '🌿 제철 나물과 고기 반찬의 완벽한 조화\n✨ 매일 바뀌는 식단으로 질릴 틈 없어요\n💰 직장인 월 정기 결제 시 15% 할인\n▶ 주문하기', '', 300000.00, 1500);
