INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11301, 1, '🔥 입맛 돋우는 매콤 쭈꾸미 볶음', '', '✨ 탱글탱글한 식감과 중독성 있는 매운맛\n💎 밥 위에 얹어 슥슥 비벼 먹으면 한 그릇 뚝딱\n📌 마요네즈 소스와 깻잎 쌈 세트 증정\n▶ 지금 주문하기', '', 1590000.00, 7950),
(11302, 1, '🍰 촉촉한 수제 당근 케이크', '', '🥕 유기농 당근과 고소한 견과류의 만남\n✨ 꾸덕한 크림치즈 프로스팅이 일품\n💰 홀케이크 예약 시 10% 할인 혜택\n▶ 예약하러 가기', '', 980000.00, 4900),
(11303, 1, '🍣 바다의 우유! 초신선 생굴 1kg', '', '🌊 통영 앞바다에서 갓 건져 올린 신선함\n💎 초장과 레몬즙만 있으면 준비 끝\n🚀 산지 직송 당일 배송 원칙 준수\n▶ 신선 배송 신청', '', 370000.00, 1850),
(11304, 1, '🍜 국물 맛이 끝내주는 잔치국수', '', '🥢 멸치와 다시마로 우려낸 깔끔한 육수\n✨ 고명까지 다 들어있는 초간편 패키지\n💰 5개 묶음 구매 시 역대급 가성비 특가\n▶ 겟하세요', '', 1660000.00, 8300),
(11305, 1, '🥗 구운 버섯과 곤약면 샐러드', '', '🍄 향긋한 버섯 풍미와 가벼운 곤약의 조화\n✨ 다이어트 중 면 요리가 생각날 때 강추\n🎯 정기 구독 시 매회 500원 할인\n▶ 식단 보기', '', 1050000.00, 5250),
(11306, 1, '🥘 정통 멕시칸 타코 홈키트', '', '🇲🇽 집에서 즐기는 멕시코의 열정적인 맛\n✨ 또띠아, 고기, 살사 소스 완벽 구성\n📌 홈파티 이색 메뉴로 강력 추천드립니다\n▶ 메뉴 보기', '', 440000.00, 2200),
(11307, 1, '🍗 마늘 치킨의 진수! 흑마늘 통닭', '', '✨ 건강까지 생각한 깊고 진한 마늘의 맛\n🔥 겉은 바삭하고 속은 촉촉한 황금 비율\n💰 리뷰 약속 시 치즈볼 4개 서비스\n▶ 주문하기', '', 1730000.00, 8650),
(11308, 1, '🥤 리얼 딸기 라떼 원액 500ml', '', '🍓 딸기 과육이 씹히는 달콤한 즐거움\n✨ 우유만 부으면 카페 딸기 라떼 완성\n🎁 2병 세트 구매 시 전용 머그컵 증정\n▶ 구매하기', '', 1120000.00, 5600),
(11309, 1, '🥘 야들야들한 한우 소곱창 구이', '', '🔥 곱이 가득! 씹을수록 고소한 풍미\n✨ 감자와 떡 사리까지 알차게 들어있어요\n📌 오늘 저녁 소주 한 잔 안주로 딱!\n▶ 주문하기', '', 510000.00, 2550),
(11310, 1, '🥯 블루베리 가득 수제 베이글', '', '🥯 상큼한 블루베리가 콕콕 박힌 쫄깃함\n✨ 크림치즈와 함께 먹으면 찰떡궁합\n💰 오전 타임 한정 아메리카노 세트 할인\n▶ 쇼핑하기', '', 1800000.00, 9000),
(11311, 1, '🍲 구수한 시골 맛, 차돌 청국장', '', '✨ 냄새 걱정 없이 깊은 맛만 살렸습니다\n🔥 차돌박이를 넣어 한층 더 고소한 맛\n📌 5분 데우면 엄마 손맛 찌개 완성\n▶ 구매하기', '', 1190000.00, 5950),
(11312, 1, '🍢 추억을 부르는 소떡소떡 세트', '', '🍡 휴게소 1등 간식을 이제 집에서 간편하게\n✨ 매콤달콤 소스가 넉넉히 들어있어요\n💰 10개입 대용량 팩 파격 세일 중\n▶ 겟하세요', '', 580000.00, 2900),
(11313, 1, '🍛 깊은 풍미의 숙성 고체 카레', '', '🇯🇵 72시간 숙성해 깊이가 다른 카레 맛\n✨ 토핑용 마늘 후레이크 기본 증정\n🎯 바쁜 직장인의 든든한 비상식량\n▶ 확인하기', '', 1870000.00, 9350),
(11314, 1, '🥨 바삭함이 살아있는 츄러스 프레첼', '', '🥨 시나몬 슈가의 달콤한 유혹\n✨ 영화 보며 즐기기 좋은 핑거 푸드\n💰 신제품 런칭 기념 2+1 이벤트\n▶ 예약하기', '', 1260000.00, 6300),
(11315, 1, '🦞 통통한 자숙 랍스터 2마리', '', '🌊 귀찮은 손질 없이 데우기만 하세요\n💎 버터 구이나 찜으로 다양하게 활용 가능\n🔥 단 3일간! 시즌 종료 파격 할인가\n▶ 주문하기', '', 650000.00, 3250),
(11316, 1, ' dumpling의 품격! 육즙 고기 왕만두', '', '🥟 얇은 피 속에 꽉 찬 속 재료의 감동\n✨ 찜기에 쪄서 먹으면 맛집 부럽지 않아요\n💰 1+1 기획 구성, 지금이 쟁여둘 기회\n▶ 더 보기', '', 1940000.00, 9700),
(11317, 1, '🥦 산지직송! 신선한 브로콜리 1kg', '', '🚜 밭에서 갓 수확해 영양이 그대로\n✨ 살짝 데쳐 초장이나 소스에 찍어 드세요\n💰 산지 직거래로 마트보다 30% 저렴\n▶ 신청하기', '', 1330000.00, 6650),
(11318, 1, '🥘 매콤달콤 춘천식 닭갈비 2인분', '', '🔥 국내산 닭다리살로 만든 부드러운 맛\n✨ 고구마와 떡 사리가 듬뿍 들어있어요\n📌 볶음밥용 김가루 서비스 포함 구성\n▶ 주문하기', '', 720000.00, 3600),
(11319, 1, '☕ 고소함의 끝판왕! 브라질 세라도', '', '✨ 견과류의 고소함과 낮은 산미의 조화\n💎 호불호 없는 데일리 원두로 추천\n💰 당일 로스팅 원두만 신선하게 배송\n▶ 구매하기', '', 110000.00, 550),
(11320, 1, '🥪 아삭한 해쉬브라운 샌드위치', '', '🥔 바삭한 해쉬브라운과 계란의 만남\n✨ 아침 식사 대용으로 든든하고 맛있어요\n🎯 단체 예약 시 맞춤 스티커 무료 제작\n▶ 문의하기', '', 1400000.00, 7000),
(11321, 1, '🍲 속이 뻥 뚫리는 김치 콩나물국', '', '✨ 술 마신 다음 날 해장국으로 1순위\n🔥 시원하고 칼칼한 국물 맛이 일품\n📌 간편 파우치 형태로 보관도 쉬워요\n▶ 선물하기', '', 790000.00, 3950),
(11322, 1, '🥩 육즙 가득! 프리미엄 토마호크', '', '🥩 압도적인 비주얼과 압도적인 육향\n✨ 캠핑의 꽃, 스테이크의 왕을 만나보세요\n💰 오늘 주문 시 허브 시즈닝 증정\n▶ 쇼핑하기', '', 180000.00, 900),
(11323, 1, '🥣 보양의 정석! 한우 사골 죽', '', '💎 진한 사골 육수에 정성을 다해 끓였습니다\n✨ 기력 회복이 필요한 분들께 선물하세요\n📌 멸균 포장으로 상온 보관이 가능합니다\n▶ 확인하기', '', 1470000.00, 7350),
(11324, 1, '🍡 쫀득쫀득 수제 가래떡 2kg', '', '💖 갓 뽑아낸 떡의 쫄깃함을 그대로\n✨ 떡볶이용, 구이용으로 활용도 만점\n🎁 명절 선물용 실속 패키지 출시\n▶ 더 보기', '', 860000.00, 4300),
(11325, 1, '🍕 페퍼로니 폭탄 뉴욕 스타일 피자', '', '🧀 짭조름한 페퍼로니가 빈틈없이 꽉\n🔥 오븐이나 에어프라이어로 갓 구운 맛\n💰 주말 한정 방문 포장 40% 할인\n▶ 주문하기', '', 250000.00, 1250),
(11326, 1, '🍝 트러플 향 가득 크림 파스타 밀키트', '', '🍄 고급스러운 트러플 풍미를 내 집에서\n✨ 우유와 생크림으로 낸 진한 소스 맛\n📌 홈파티나 기념일 메뉴로 강력 추천\n▶ 구매하기', '', 1540000.00, 7700),
(11327, 1, '🍲 시원한 국물 맛! 백상합탕 2인분', '', '🌊 해캄 완료! 신선한 조개가 한가득\n✨ 소주 안주로, 깔끔한 국물 요리로 최고\n💰 12,900원의 행복, 지금 만나보세요\n▶ 겟하세요', '', 930000.00, 4650),
(11328, 1, '🍗 바삭바삭 수제 안심 텐더', '', '🔥 닭안심살로 만들어 부드러운 식감\n✨ 아이들 간식이나 샐러드 토핑으로 딱\n📌 리뷰 작성 시 머스타드 소스 증정\n▶ 바로가기', '', 320000.00, 1600),
(11329, 1, '🍹 상큼함 충전! 유자 에이드 원액', '', '🍋 비타민 가득한 유자의 맛 그대로\n✨ 탄산수만 넣으면 상큼한 음료 완성\n💰 2병 구매 시 전용 머들러 증정\n▶ 쇼핑하기', '', 1610000.00, 8050),
(11330, 1, '🍳 폭신폭신한 수플레 팬케이크 세트', '', '✨ 입안에서 녹아내리는 구름 같은 식감\n💎 휘핑크림과 메이플 시럽 기본 포함\n📌 주말 브런치를 근사하게 즐기세요\n▶ 구경하기', '', 1000000.00, 5000),
(11331, 1, '🥘 매콤 아삭 코다리 조림 밀키트', '', '🐟 살이 꽉 찬 명품 코다리만 골랐습니다\n✨ 비법 양념장과 시래기의 환상 궁합\n💰 오늘 하루만 선착순 배송비 무료\n▶ 주문하기', '', 390000.00, 1950),
(11332, 1, '🍩 꾸덕한 크림 치즈 수제 도넛', '', '💖 크림 치즈가 빈틈없이 가득 들어있어요\n✨ 달콤 짭짤한 맛의 중독성에 주의하세요\n🎯 단체 간식 주문 시 박스당 할인 혜택\n▶ 메뉴 보기', '', 1680000.00, 8400),
(11333, 1, '🍲 진한 사골 육수의 수육 국밥', '', '✨ 잡내 없이 깔끔한 국물과 부드러운 수육\n🔥 밥 한 공기 말아 먹으면 세상 든든함\n📌 한정 수량 매일 조리 판매 중\n▶ 겟하기', '', 1070000.00, 5350),
(11334, 1, '🥨 단짠의 매력! 솔티드 카라멜 프레첼', '', '🥨 직접 끓인 카라멜 소스의 진한 풍미\n✨ 짭짤한 소금이 단맛을 더욱 극대화\n💰 온라인 단독! 5개 묶음 20% 할인\n▶ 확인하기', '', 460000.00, 2300),
(11335, 1, '🥩 1등급 한우 등심 정기 배송', '', '🥩 매주 최상의 마블링만 골라 배송해 드려요\n✨ 스테이크용/구이용 선택 가능\n💰 첫 달 구독료 30% 캐시백 이벤트\n▶ 신청하기', '', 1750000.00, 8750),
(11336, 1, '🥗 훈제 연어와 케이퍼 샐러드', '', '🐟 풍미 가득한 훈제 연어와 신선한 채소\n✨ 어니언 드레싱으로 깔끔한 마무리\n📌 아침 식단으로 가볍게 시작하세요\n▶ 더 보기', '', 1140000.00, 5700),
(11337, 1, '🍲 마라탕 매니아를 위한 소고기 세트', '', '🔥 얼얼한 마라향에 소고기 추가는 국룰\n✨ 푸주, 건두부, 옥수수면 풀패키지\n💰 지금 주문 시 꿔바로우 미니 증정\n▶ 주문하기', '', 530000.00, 2650),
(11338, 1, '🍘 가마솥에 구운 현미 누룽지 1kg', '', '✨ 국내산 현미 100%로 만든 건강 간식\n📌 끓여 먹으면 고소한 숭늉 완성\n💰 직거래 특가로 유통 거품을 뺐습니다\n▶ 구매하기', '', 1820000.00, 9100),
(11339, 1, '🍜 정통 돈코츠 라멘 밀키트 2인분', '', '🥢 24시간 우려낸 진한 사골 육수의 맛\n✨ 차슈와 아지타마고까지 들어있어요\n📌 10분 만에 완성하는 일본 정통 라멘\n▶ 겟하기', '', 1210000.00, 6050),
(11340, 1, '🥣 영양 가득 단팥죽과 새알심', '', '✨ 팥의 진한 맛과 쫀득한 새알심의 만남\n💎 겨울철 별미로 가족 모두 즐겨보세요\n💰 5팩 구매 시 1팩 추가 증정 이벤트\n▶ 쇼핑하기', '', 600000.00, 3000),
(11341, 1, '🥘 밥도둑! 묵은지 고등어 조림', '', '🐟 잘 익은 묵은지와 고등어의 환상 조화\n✨ 엄마 손맛 그리울 때 최고의 선택\n📌 15분만 끓이면 완성되는 맛집 요리\n▶ 구매하기', '', 1890000.00, 9450),
(11342, 1, '🥨 천연 발효종 무설탕 호밀 빵', '', '🥖 건강을 생각한 담백하고 구수한 맛\n✨ 식사 대용이나 샌드위치용으로 추천\n💰 매일 아침 구워 당일 발송해 드려요\n▶ 예약하기', '', 1280000.00, 6400),
(11343, 1, '🥩 숯불향 가득 돼지 양념 구이', '', '🔥 특제 소스에 숙성해 부드러운 육질\n✨ 아이들이 좋아하는 단짠의 정석\n💰 캠핑/여행용 대용량 가성비 끝판왕\n▶ 주문하기', '', 670000.00, 3350),
(11344, 1, '🍹 상큼함 폭발! 청포도 에이드 원액', '', '🍇 청포도 과육이 살아있는 싱그러운 맛\n✨ 홈카페 에이드, 스무디 베이스로 활용\n🎁 2병 구매 시 전용 보틀 증정\n▶ 확인하기', '', 1960000.00, 9800),
(11345, 1, '🍣 입에서 녹는 참치 뱃살 홈세트', '', '🌊 최고급 참다랑어 대뱃살(오도로) 구성\n💎 전문점 가격의 절반으로 즐기는 사치\n🚀 초저온 냉동 포장으로 선도 완벽 유지\n▶ 주문하기', '', 1350000.00, 6750),
(11346, 1, '🥟 겉바속촉! 수제 튀김 만두', '', '🥟 당면과 야채가 꽉 찬 옛날식 만두\n✨ 분식과 함께 먹으면 더 맛있는 별미\n💰 3봉 세트 구매 시 비법 소스 증정\n▶ 담으러 가기', '', 740000.00, 3700),
(11347, 1, '🍲 기력 회복! 명품 전복 삼계탕', '', '✨ 큼직한 전복이 들어간 프리미엄 보양식\n🔥 가마솥 방식으로 깊고 진하게 고았습니다\n📌 부모님 건강 선물로 적극 추천드립니다\n▶ 구매하기', '', 130000.00, 650),
(11348, 1, '🍝 바질 페스토 파스타 밀키트', '', '🌿 싱그러운 바질 향과 견과류의 고소함\n✨ 셰프의 레시피로 10분 만에 완성\n💰 런칭 기념 기간 한정 20% 할인\n▶ 보러가기', '', 1420000.00, 7100),
(11349, 1, '🥨 시나몬 롤 프레첼 신제품 출시', '', '🥯 시나몬의 향긋함과 설탕의 달콤함\n✨ 커피와 함께 즐기는 여유로운 간식\n🎯 오늘 주문 시 2+1 자동 적용 혜택\n▶ 겟하세요', '', 810000.00, 4050),
(11350, 1, '🍱 정성 가득 12첩 한정식 도시락', '', '🍱 매일 신선한 재료로 만든 든든한 한 끼\n✨ 한식 전문가의 균형 잡힌 식단 구성\n💰 월 정기 결제 시 포인트 10% 적립\n▶ 주문하기', '', 200000.00, 1000);
