INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11351, 1, '🔥 밥도둑 종결자! 간장게장 2kg', '', '✨ 비법 씨간장으로 담가 짜지 않고 깊은 맛\n💎 100% 국내산 알배기 꽃게만 엄선\n📌 게딱지에 비벼 먹는 밥 한 숟가락의 행복\n▶ 지금 주문하기', '', 1490000.00, 7450),
(11352, 1, '🍰 꾸덕함 가득! 황치즈 파운드 케이크', '', '🧀 진한 체다 치즈의 풍미가 입안 가득\n✨ 단짠단짠의 완벽한 조화를 경험하세요\n💰 2개 구매 시 10% 추가 할인 혜택\n▶ 달콤함 충전', '', 880000.00, 4400),
(11353, 1, '🍣 쫄깃쫄깃! 완도산 대광어회', '', '🌊 산지 직송으로 즐기는 찰진 식감\n💎 두툼하게 썰어 씹는 맛이 일품입니다\n🚀 오늘 오후 3시 주문 시 내일 새벽 도착\n▶ 신선 배송 신청', '', 270000.00, 1350),
(11354, 1, '🍜 속 풀리는 시원한 바지락 칼국수', '', '🥢 신선한 바지락이 듬뿍! 깔끔한 국물\n✨ 쫄깃한 수제 면발로 전문점 맛 그대로\n💰 캠핑용 간편 패키지 특가 판매 중\n▶ 겟하세요', '', 1560000.00, 7800),
(11355, 1, '🥗 수비드 닭가슴살 샐러드 도시락', '', '🥑 저온 숙성으로 퍽퍽함 없이 촉촉한 육질\n✨ 신선한 채소와 오리엔탈 드레싱의 만남\n🎯 식단 관리 정기 배송 서비스 신청\n▶ 식단 보기', '', 950000.00, 4750),
(11356, 1, '🥘 정통 태국식 똠양꿍 밀키트', '', '🇹🇭 세계 3대 스푼 요리의 오묘한 매력\n✨ 통통한 새우와 향긋한 레몬그라스의 조화\n📌 이국적인 맛이 그리울 때 최고의 선택\n▶ 메뉴 보기', '', 340000.00, 1700),
(11357, 1, '🍗 옛날 방식 그대로! 가마솥 통닭', '', '✨ 얇은 튀김옷으로 느끼하지 않고 고소하게\n🔥 추억의 노란 봉투에 담아 배달해 드립니다\n💰 평일 주문 시 배달료 전액 무료\n▶ 주문하기', '', 1630000.00, 8150),
(11358, 1, '🥤 리얼 블루베리 착즙 주스 1L', '', '🍇 물 한 방울 안 섞인 100% 원액\n✨ 눈 건강과 활력을 위한 매일 한 잔\n🎁 3병 세트 구매 시 선물용 쇼핑백 증정\n▶ 구매하기', '', 1020000.00, 5100),
(11359, 1, '🥘 야들야들한 불막창 볶음', '', '🔥 잡내 없이 깔끔하고 화끈하게 매운맛\n✨ 깻잎과 당면 사리 넣어 볶으면 완벽 야식\n📌 리뷰 이벤트 참여 시 치즈 사리 공짜\n▶ 주문하기', '', 410000.00, 2050),
(11360, 1, '🥯 고소한 소금빵 베이글 5개입', '', '🥯 소금빵의 풍미와 베이글의 쫄깃함의 조화\n✨ 에어프라이어 3분이면 갓 구운 맛\n💰 마감 세일 30% 파격 할인 중\n▶ 쇼핑하기', '', 1700000.00, 8500),
(11361, 1, '🍲 엄마 손맛 그대로, 들깨 미역국', '', '✨ 들깨 가루를 듬뿍 넣어 구수하고 진한 맛\n🔥 생일이나 기력 회복이 필요할 때 추천\n📌 10분만 끓이면 완성되는 간편 보양식\n▶ 구매하기', '', 1090000.00, 5450),
(11362, 1, '🍢 쫀득한 부산 물떡 꼬치 세트', '', '🌊 부산 어묵 골목의 그 맛을 집에서\n✨ 비법 육수 스프가 포함되어 정말 쉬워요\n💰 아이들 간식용 대용량 팩 출시\n▶ 겟하세요', '', 480000.00, 2400),
(11363, 1, '🍛 풍미 가득한 소고기 하이라이스', '', '🇯🇵 정통 데미글라스 소스의 깊고 진한 맛\n✨ 소고기와 양파를 듬뿍 넣어 식감이 최고\n🎯 바쁜 아침 든든한 한 끼 식사 해결\n▶ 확인하기', '', 1770000.00, 8850),
(11364, 1, '🥨 바삭한 시나몬 슈가 프레첼 칩', '', '🥨 한 번 열면 멈출 수 없는 인간 사료\n✨ 맥주 안주나 간식으로 가볍게 즐기세요\n💰 온라인 단독 1+1 창고 대방출\n▶ 예약하기', '', 1160000.00, 5800),
(11365, 1, '🦞 수율 95%! 러시아산 박달 대게', '', '🌊 속살이 꽉 찬 프리미엄 대게만 엄선\n💎 손질까지 다 해서 보내드리니 편하게 드세요\n🔥 산지 직송 신선도 보장제 운영 중\n▶ 주문하기', '', 550000.00, 2750),
(11366, 1, '🥟 얇은 피 수제 김치 왕만두', '', '🥟 아삭한 김치와 고기의 황금 비율\n✨ 쪄먹어도, 국에 넣어도 맛있는 만능 만두\n💰 3kg 대용량 구매 시 무료 배송\n▶ 더 보기', '', 1840000.00, 9200),
(11367, 1, '🥦 신선함 가득! 제주 콜리플라워 1kg', '', '🚜 제주 해풍 맞고 자라 더 단단하고 고소한\n✨ 샐러드나 스테이크 가니쉬로 활용하세요\n💰 산지 직송으로 신선함을 집 앞까지\n▶ 신청하기', '', 1230000.00, 6150),
(11368, 1, '🥘 화끈한 불향! 오징어 볶음 밀키트', '', '🔥 통통한 오징어와 아삭한 야채의 조화\n✨ 남은 양념에 밥 볶아 먹으면 인생 맛집\n📌 10분 완성 레시피로 요리 초보도 뚝딱\n▶ 주문하기', '', 620000.00, 3100),
(11369, 1, '☕ 산뜻한 산미! 에티오피아 원두 500g', '', '✨ 꽃향기와 과일향의 우아한 밸런스\n💎 기분 전환이 필요한 오후에 딱 맞는 커피\n💰 당일 로스팅 원두만 고집합니다\n▶ 구매하기', '', 1910000.00, 9550),
(11370, 1, '🥪 감자 샐러드가 듬뿍! 모닝 샌드위치', '', '🥔 부드럽고 담백한 추억의 사라다 빵 맛\n✨ 우유와 함께 먹으면 아이들 간식으로 최고\n🎯 단체 행사 간식 주문 대환영\n▶ 문의하기', '', 1300000.00, 6500),
(11371, 1, '🍲 구수하고 담백한 소고기 무국', '', '✨ 한우를 듬뿍 넣어 국물 맛이 깊고 진해요\n🔥 아이들이 밥 말아 먹기 가장 좋은 국\n📌 바쁜 아침 3분 조리 완성 패키지\n▶ 선물하기', '', 690000.00, 3450),
(11372, 1, '🥩 육질이 남다른 이베리코 목살', '', '🐷 소고기 같은 풍미와 부드러운 식감\n✨ 캠핑장 고기 파티의 주인공이 되어보세요\n💰 오늘 주문 시 와사비 소스 증정\n▶ 쇼핑하기', '', 1980000.00, 9900),
(11373, 1, '🥣 영양 만점! 잣과 해바라기씨 죽', '', '💎 견과류의 고소함을 한 그릇에 담았습니다\n✨ 소화가 잘 되어 어르신들 아침으로 추천\n📌 개별 포장으로 휴대가 간편합니다\n▶ 확인하기', '', 1370000.00, 6850),
(11374, 1, '🍡 말랑말랑 수제 꿀떡 1kg', '', '💖 깨가 톡 터지는 달콤한 유혹\n✨ 굳지 않는 특허 공법으로 더 오래 쫄깃하게\n🎁 답례품 및 행사용 떡 예약 가능\n▶ 더 보기', '', 760000.00, 3800),
(11375, 1, '🍕 치즈 덕후를 위한 콰트로 피자', '', '🧀 4가지 프리미엄 치즈의 진한 풍미\n🔥 쫄깃한 도우와 치즈의 환상적인 하모니\n💰 주말 한정 1+1 메가 세일 진행 중\n▶ 주문하기', '', 150000.00, 750),
(11376, 1, '🍝 매콤 짭짤! 엔초비 파스타 밀키트', '', '🐟 감칠맛의 정석, 엔초비와 마늘의 만남\n✨ 셰프의 비법 소스로 10분 완성\n📌 입맛 돋우는 별미 요리로 추천\n▶ 구매하기', '', 1440000.00, 7200),
(11377, 1, '🍲 시원 칼칼! 꽃게탕 2인분 밀키트', '', '🌊 알이 꽉 찬 꽃게와 미더덕이 듬뿍\n✨ 된장 베이스의 비법 양념으로 비린내 제로\n💰 지금 사면 라면 사리 2봉 증정\n▶ 겟하세요', '', 830000.00, 4150),
(11378, 1, '🍗 부드러운 닭다리살 치킨 가라아게', '', '🔥 겉은 바삭하고 속은 촉촉한 일본식 튀김\n✨ 맥주 안주나 아이들 밥반찬으로 인기\n📌 리뷰 작성 시 타르타르 소스 증정\n▶ 바로가기', '', 220000.00, 1100),
(11379, 1, '🍹 상큼 달콤! 자두 에이드 원액', '', '🍑 자두의 과즙을 그대로 살린 진한 맛\n✨ 홈메이드 에이드로 갈증을 해소하세요\n💰 2병 세트 구매 시 유리 머들러 증정\n▶ 쇼핑하기', '', 1510000.00, 7550),
(11380, 1, '🍳 정통 벨기에 와플 생지 세트', '', '✨ 구우면 퍼지는 버터의 고소한 향기\n💎 생크림과 과일로 나만의 홈카페 완성\n📌 아이들과 함께 만드는 요리 체험용 추천\n▶ 구경하기', '', 900000.00, 4500),
(11381, 1, '🥘 매콤 아삭! 순대 볶음 2인분', '', '🔥 찰순대와 야채, 비법 양념의 황금 조합\n✨ 들깨 가루가 신의 한 수인 고소한 맛\n💰 오늘만 5,000원 깜짝 할인 쿠폰 발급\n▶ 주문하기', '', 290000.00, 1450),
(11382, 1, ' donut의 정석! 우유 크림 도넛', '', '💖 퐁신한 빵 속에 우유 크림이 폭발\n✨ 당 충전이 필요한 순간, 최고의 선택\n🎯 단체 주문 시 전용 패키지 포장 가능\n▶ 메뉴 보기', '', 1580000.00, 7900),
(11383, 1, '🍲 진한 사골 육수의 사골 떡만둣국', '', '✨ 뼈째 고아낸 진한 육수와 수제 만두\n🔥 한 그릇이면 든든한 보양 한 끼 완성\n📌 명절이 아니어도 생각나는 그 맛\n▶ 겟하기', '', 970000.00, 4850),
(11384, 1, '🥨 달콤한 카라멜 팝콘 프레첼', '', '🥨 팝콘의 달콤함과 프레첼의 짭짤함\n✨ 넷플릭스 정주행 시 필수 아이템\n💰 3봉 세트 구매 시 무료 배송 혜택\n▶ 확인하기', '', 360000.00, 1800),
(11385, 1, '🥩 1++ 등급 한우 불고기 1kg', '', '🥩 야들야들한 육질과 명인 비법 양념\n✨ 남녀노소 누구나 좋아하는 최고의 반찬\n💰 구독 첫 달 한우 국거리 고기 추가 증정\n▶ 신청하기', '', 1650000.00, 8250),
(11386, 1, '🥗 단백질 폭탄! 닭가슴살 퀴노아 샐러드', '', '🥦 수퍼푸드 퀴노아로 챙기는 건강 한 끼\n✨ 포만감이 높아 다이어트 식단으로 추천\n📌 매일 새벽 배송되는 신선함을 만나보세요\n▶ 더 보기', '', 1040000.00, 5200),
(11387, 1, '🍲 마라 매니아를 위한 마라샹궈 세트', '', '🔥 볶음으로 즐기는 마라의 강렬한 중독성\n✨ 고기와 야채가 푸짐하게 들어있어요\n💰 지금 주문하면 중국 당면 사리 서비스\n▶ 주문하기', '', 430000.00, 2150),
(11388, 1, '🍘 고소한 흑미 누룽지 2kg 대용량', '', '✨ 국내산 흑미로 만들어 더욱 고소한 풍미\n📌 간식으로도, 끓여서 숭늉으로도 최고\n💰 직판가 운영으로 유통 거품을 뺐습니다\n▶ 구매하기', '', 1720000.00, 8600),
(11389, 1, '🍜 진한 미소 라멘 밀키트 2인분', '', '🍜 일본 정통 미소의 깊고 구수한 맛\n✨ 쫄깃한 생면과 차슈의 환상적인 만남\n📌 10분 만에 완성하는 도쿄 라멘의 맛\n▶ 겟하기', '', 1110000.00, 5550),
(11390, 1, '🥣 영양 가득 호박죽과 옹심이 7팩', '', '🎃 단호박의 단맛과 쫀득한 옹심이의 조화\n💎 바쁜 아침을 든든하게 채워주는 건강 죽\n💰 1주일 패키지 구매 시 전용 보울 증정\n▶ 쇼핑하기', '', 500000.00, 2500),
(11391, 1, '🥘 밥도둑 끝판왕! 매콤 명태조림', '', '🐟 살이 꽉 찬 명태와 비법 양념의 조화\n✨ 시래기 추가해서 먹으면 더 맛있는 별미\n📌 부모님 모시고 가던 맛집 그 맛 그대로\n▶ 구매하기', '', 1790000.00, 8950),
(11392, 1, '🥨 천연 발효종 무설탕 통밀 빵', '', '🥖 건강한 식단을 위한 정직한 빵\n✨ 씹을수록 느껴지는 통밀의 구수한 매력\n💰 매일 아침 구워 당일 신선 배송해 드려요\n▶ 예약하기', '', 1180000.00, 5900),
(11393, 1, '🥩 단짠의 정석, 돼지 갈비찜 밀키트', '', '🔥 과일 양념으로 숙성해 부드러운 육질\n✨ 명절 분위기 내고 싶을 때 강력 추천\n💰 캠핑/여행용 대용량 가성비 팩 출시\n▶ 주문하기', '', 570000.00, 2850),
(11394, 1, '🍹 상큼함 충전! 오미자 에이드 원액', '', '🍒 다섯 가지 맛의 조화, 건강한 달콤함\n✨ 탄산수나 따뜻한 물에 타서 즐기세요\n🎁 2병 구매 시 전용 텀블러 기본 제공\n▶ 확인하기', '', 1860000.00, 9300),
(11395, 1, '🍣 입에서 살살 녹는 연어 필렛 500g', '', '🌊 초신선 슈페리어 등급 생연어만 사용\n💎 회, 초밥, 샐러드로 다양하게 활용 가능\n🚀 아이스팩 가득 담아 신선하게 배송\n▶ 주문하기', '', 1250000.00, 6250),
(11396, 1, '🥟 겉바속촉 수제 야끼만두', '', '🥟 분식집에서 먹던 그 바삭한 만두 맛\n✨ 떡볶이 국물에 찍어 먹으면 환상의 궁합\n💰 3봉 세트 구매 시 비법 소스 증정\n▶ 담으러 가기', '', 640000.00, 3200),
(11397, 1, '🍲 원기 회복! 전복 낙지 삼계탕', '', '✨ 바다와 육지의 보양이 만나다\n🔥 귀한 분께 선물하기 좋은 명품 보양식\n📌 부모님 기력 보충 선물로 적극 추천\n▶ 구매하기', '', 1930000.00, 9650),
(11398, 1, '🍝 쉬림프 로제 파스타 밀키트', '', '🦐 통통한 새우와 부드러운 크림의 조화\n✨ 10분 만에 근사한 레스토랑 요리 완성\n💰 런칭 기념 기간 한정 30% 할인 이벤트\n▶ 보러가기', '', 1320000.00, 6600),
(11399, 1, '🥨 초코 퐁당 프레첼 신제품', '', '🍫 진한 벨기에 초콜릿의 달콤한 유혹\n✨ 커피와 함께 즐기는 우아한 간식 시간\n🎯 오늘 주문 시 2+1 혜택을 놓치지 마세요\n▶ 겟하세요', '', 710000.00, 3550),
(11400, 1, '🍱 정갈한 10첩 반상 한식 도시락', '', '🍱 매일 신선한 재료로 구성한 알찬 한 끼\n✨ 영양사와 요리사가 함께 만든 건강 식단\n💰 직장인 정기 결제 시 추가 10% 포인트\n▶ 주문하기', '', 100000.00, 500);
