INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11401, 1, '🔥 입안 가득 퍼지는 불향! 직화 제육볶음', '', '✨ 비법 고추장 양념으로 살린 화끈한 감칠맛\n💎 쌈 채소와 함께라면 밥 두 그릇 순삭 보장\n📌 1인분씩 소분 포장되어 혼밥족에게 강추\n▶ 지금 주문하기', '', 1390000.00, 6950),
(11402, 1, '🍰 부드러운 유혹, 수제 생딸기 케이크', '', '🍓 매일 아침 공수하는 신선한 딸기가 듬뿍\n✨ 동물성 생크림 100%의 깔끔하고 진한 맛\n💰 기념일 예약 시 커스텀 토퍼 증정\n▶ 예약하러 가기', '', 780000.00, 3900),
(11403, 1, '🍣 바다를 한 입에! 신선한 멍게 1kg', '', '🌊 통영의 바다 향을 그대로 머금은 달큰함\n💎 초장에 콕 찍어 먹으면 안주로 최고입니다\n🚀 산지 직송 시스템으로 신선도 끝판왕\n▶ 신선 배송 신청', '', 170000.00, 850),
(11404, 1, '🍜 속까지 시원해지는 해물 짬뽕 밀키트', '', '🥢 오징어, 홍합, 새우가 듬뿍 들어간 진한 국물\n✨ 불맛 소스로 전문점 퀄리티를 집에서 구현\n💰 2인분 세트 구매 시 군만두 서비스 증정\n▶ 겟하세요', '', 1460000.00, 7300),
(11405, 1, '🥗 바삭한 치킨 텐더 샐러드 보울', '', '🥑 겉바속촉 치킨 안심과 신선한 채소의 조화\n✨ 허니 머스타드 드레싱으로 입맛을 돋우세요\n🎯 건강한 한 끼 식단, 정기 배송 가능\n▶ 식단 보기', '', 850000.00, 4250),
(11406, 1, '🥘 정통 이탈리안 라자냐 홈키트', '', '🇮🇳 층층이 쌓인 고기 소스와 치즈의 깊은 풍미\n✨ 오븐이나 에어프라이어로 15분이면 완성\n📌 홈파티 분위기를 업그레이드할 최고의 선택\n▶ 메뉴 보기', '', 240000.00, 1200),
(11407, 1, '🍗 마늘의 성지! 의성 마늘 후라이드', '', '✨ 알싸한 마늘과 바삭한 튀김옷의 환상 궁합\n🔥 한 번 맛보면 멈출 수 없는 중독성 강한 맛\n💰 배달 앱 리뷰 작성 시 치즈볼 증정 이벤트\n▶ 주문하기', '', 1530000.00, 7650),
(11408, 1, '🥤 100% 리얼 사과 착즙 주스 1L', '', '🍎 설탕 NO! 물 NO! 사과 본연의 달콤함\n✨ 아이들에게 안심하고 먹일 수 있는 건강 간식\n🎁 5병 묶음 구매 시 무료 배송 혜택\n▶ 구매하기', '', 920000.00, 4600),
(11409, 1, '🥘 쫄깃쫄깃 끝판왕! 양념 소막창', '', '🔥 잡내를 완벽히 제거해 고소함만 남겼습니다\n✨ 숯불에 구우면 더 맛있는 야식 1순위 메뉴\n📌 오늘 저녁, 시원한 맥주 한 잔과 어떠세요?\n▶ 주문하기', '', 310000.00, 1550),
(11410, 1, '🥯 어니언 크림치즈 듬뿍 베이글', '', '🥯 향긋한 구운 양파 향과 꾸덕한 크림치즈\n✨ 브런치 카페 부럽지 않은 고품격 아침 식사\n💰 신제품 출시 기념 2+1 깜짝 이벤트\n▶ 쇼핑하기', '', 1600000.00, 8000),
(11411, 1, '🍲 속 풀리는 뜨끈한 소고기 미역국', '', '✨ 한우를 아낌없이 넣어 깊고 구수한 국물 맛\n🔥 생일이나 기력 회복이 필요한 날 추천합니다\n📌 5분만 데우면 정성 가득한 한 끼 완성\n▶ 구매하기', '', 990000.00, 4950),
(11412, 1, '🍢 길거리 그 맛 그대로! 매콤 떡꼬치', '', '🍡 떡집 가래떡을 튀겨 겉은 바삭 속은 쫄깃\n✨ 비법 소스가 넉넉해 추억의 맛 소환 완료\n💰 10개 세트 가성비 가격으로 만나보세요\n▶ 겟하세요', '', 380000.00, 1900),
(11413, 1, '🍛 풍미 가득 일본식 드라이 카레', '', '🇯🇵 물 없이 볶아 고기의 맛을 극대화했습니다\n✨ 반숙 계란후라이와 찰떡궁합을 자랑해요\n🎯 간편하게 즐기는 특별한 미식 경험\n▶ 확인하기', '', 1670000.00, 8350),
(11414, 1, '🥨 바삭하고 고소한 참깨 프레첼 칩', '', '🥨 씹을수록 고소함이 터지는 영양 간식\n✨ 샐러드 토핑이나 맥주 안주로 제격입니다\n💰 온라인 단독! 4봉 묶음 특가 세일 중\n▶ 예약하기', '', 1060000.00, 5300),
(11415, 1, '🦞 속이 꽉 찬 자숙 홍게 5마리', '', '🌊 산지에서 쪄서 바로 보내 선도가 살아있어요\n💎 라면에 넣어 먹으면 명품 해물라면 탄생\n🔥 한정 수량! 지금 주문해야 내일 도착\n▶ 주문하기', '', 450000.00, 2250),
(11416, 1, '🥟 통새우가 톡톡! 새우 하가우', '', '🥟 얇고 투명한 피 속에 통새우가 가득\n✨ 홍콩 현지 딤섬 전문점의 맛을 집에서\n💰 500g 대용량 지퍼백 포장으로 넉넉하게\n▶ 더 보기', '', 1740000.00, 8700),
(11417, 1, '🥦 무농약으로 키운 신선한 양배추 1통', '', '🚜 아삭한 식감과 달큰한 맛이 살아있는 채소\n✨ 샐러드나 쌈, 즙으로 다양하게 활용하세요\n💰 농가 직거래로 중간 마진을 싹 뺐습니다\n▶ 신청하기', '', 1130000.00, 5650),
(11418, 1, '🥘 춘천 명물! 치즈 닭갈비 2인분', '', '🔥 매콤한 닭갈비 위에 고소한 치즈가 폭포처럼\n✨ 우동 사리와 야채가 듬뿍 포함된 풀패키지\n📌 캠핑장 메인 요리로 이보다 좋을 수 없다\n▶ 주문하기', '', 520000.00, 2600),
(11419, 1, '☕ 묵직한 바디감! 인도네시아 만델링', '', '✨ 흙내음과 초콜릿 풍미가 어우러진 깊은 맛\n💎 카페인 충전이 절실한 아침에 추천합니다\n💰 신선함을 위해 주문 후 즉시 로스팅 시작\n▶ 구매하기', '', 1810000.00, 9050),
(11420, 1, '🥪 속이 꽉 찬 프리미엄 햄치즈 샌드위치', '', '🥗 신선한 양상추와 수제 소스의 완벽한 조화\n✨ 바쁜 출근길, 든든한 아침을 책임집니다\n🎯 단체 도시락 배달 주문 시 음료 서비스\n▶ 문의하기', '', 1200000.00, 6000),
(11421, 1, '🍲 구수하고 진한 시골 할머니 된장찌개', '', '✨ 5년 숙성 된장으로 맛을 낸 깊은 감칠맛\n🔥 차돌박이와 두부가 듬뿍 들어있어 든든해요\n📌 간편 조리팩으로 여행 시 필수 아이템\n▶ 선물하기', '', 590000.00, 2950),
(11422, 1, '🥩 육즙 폭발! 수비드 토마호크 스테이크', '', '🥩 압도적인 비주얼로 파티 분위기 끝판왕\n✨ 저온 조리로 속까지 부드럽게 익혔습니다\n💰 지금 구매 시 스테이크 시즈닝 3종 증정\n▶ 쇼핑하기', '', 1880000.00, 9400),
(11423, 1, '🥣 영양 가득 든든한 쇠고기 야채죽', '', '💎 고소한 소고기와 7가지 야채의 건강한 만남\n✨ 소화가 잘 되어 아침 식사 대용으로 최고\n📌 멸균 파우치로 실온 보관이 가능해 편리해요\n▶ 확인하기', '', 1270000.00, 6350),
(11424, 1, '🍡 달콤 짭짤한 간장 기름 떡볶이', '', '💖 통인시장 스타일의 고소하고 바삭한 맛\n✨ 맥주 안주나 별미 간식으로 인기 폭발 중\n🎁 3인분 구매 시 추가 1인분 증정 이벤트\n▶ 더 보기', '', 660000.00, 3300),
(11425, 1, '🍕 화끈하게 매운 핫치킨 피자', '', '🧀 매콤한 치킨과 부드러운 치즈의 환상 조화\n🔥 도우 끝까지 토핑을 꽉 채워 넣었습니다\n💰 방문 포장 시 콜라 1.25L 무료 증정\n▶ 주문하기', '', 1950000.00, 9750),
(11426, 1, '🍝 바질 페스토 냉파스타 밀키트', '', '🌿 상큼한 바질 향과 방울토마토의 싱그러움\n✨ 입맛 없는 여름철 별미로 강력 추천드립니다\n📌 5분 삶고 버무리면 끝나는 초간편 요리\n▶ 구매하기', '', 1340000.00, 6700),
(11427, 1, '🍲 시원한 국물 맛이 일품인 조개탕', '', '🌊 해캄이 잘 된 신선한 바지락과 백합이 가득\n✨ 소주 안주로 먹으면 다음 날 숙취 걱정 끝\n💰 12,900원 특가로 즐기는 해산물의 풍미\n▶ 겟하세요', '', 730000.00, 3650),
(11428, 1, '🍗 아이들 간식으로 딱! 순살 닭강정', '', '🔥 달콤하고 짭짤한 소스가 골고루 입혀진 맛\n✨ 식어도 바삭함을 유지하는 비법 튀김옷\n📌 리뷰 작성 시 고구마 튀김 서비스 제공\n▶ 바로가기', '', 120000.00, 600),
(11429, 1, '🍹 상큼함 폭발! 한라봉 에이드 원액', '', '🍊 제주산 한라봉의 과즙을 듬뿍 담았습니다\n✨ 홈카페에서 즐기는 시원한 제주의 향기\n💰 2병 구매 시 전용 유리병 증정 행사 중\n▶ 쇼핑하기', '', 1410000.00, 7050),
(11430, 1, '🍳 부드러운 수플레 오므라이스 키트', '', '✨ 입안에서 녹아내리는 폭신한 계란의 감동\n💎 명장 레시피로 만든 데미글라스 소스 포함\n📌 특별한 날 아이들을 위한 영양 만점 메뉴\n▶ 구경하기', '', 800000.00, 4000),
(11431, 1, '🥘 아삭함과 매콤함의 조화, 콩나물 불고기', '', '🔥 콩불 맛집의 비법 양념장 그대로 담았습니다\n✨ 볶음밥용 김가루와 치즈가 기본 구성\n💰 오늘 하루 선착순 1,000원 추가 할인\n▶ 주문하기', '', 190000.00, 950),
(11432, 1, '🍩 꾸덕한 초코 필링이 가득한 수제 도넛', '', '💖 벨기에산 다크 초콜릿의 깊고 진한 달콤함\n✨ 당 충전이 필요한 오후의 완벽한 파트너\n🎯 어린이집 단체 간식 주문 시 맞춤 배달\n▶ 메뉴 보기', '', 1480000.00, 7400),
(11433, 1, '🍲 진한 사골 국물의 고기 국밥 2인분', '', '✨ 48시간 우려낸 진국 사골 육수의 풍미\n🔥 고기를 아낌없이 넣어 한 그릇으로 배불러요\n📌 집에서 즐기는 부산 국밥 맛집의 퀄리티\n▶ 겟하기', '', 870000.00, 4350),
(11434, 1, '🥨 단짠의 끝판왕, 솔티드 카라멜 프레첼', '', '🥨 직접 끓인 카라멜과 소금의 환상적인 하모니\n✨ 중독성 강한 맛으로 마약 프레첼이라 불려요\n💰 5개 구매 시 1개 추가 증정 이벤트 중\n▶ 확인하기', '', 260000.00, 1300),
(11435, 1, '🥩 1등급 한우 채끝 스테이크 정기 배송', '', '🥩 매주 최상의 마블링만 골라 집 앞까지 배송\n✨ 셰프가 제안하는 가니쉬와 소스 포함 구성\n💰 첫 달 구독 시 스테이크 나이프 세트 증정\n▶ 신청하기', '', 1550000.00, 7750),
(11436, 1, '🥗 고소한 견과류와 리코타 치즈 샐러드', '', '🧀 매일 아침 직접 만든 신선한 리코타 치즈\n✨ 발사믹 드레싱으로 즐기는 건강한 한 끼\n📌 식단 관리 중에도 맛있게 즐길 수 있어요\n▶ 더 보기', '', 940000.00, 4700),
(11437, 1, '🍲 마라탕 매니아를 위한 소고기 풀패키지', '', '🔥 화끈하고 얼얼한 마라의 정석을 맛보세요\n✨ 중국 당면, 푸주, 건두부까지 모두 포함\n💰 오늘 주문 시 꿔바로우 미니 사이즈 서비스\n▶ 주문하기', '', 330000.00, 1650),
(11438, 1, '🍘 가마솥 방식으로 구운 찰현미 누룽지', '', '✨ 100% 국내산 찰현미로 더 고소하고 바삭해요\n📌 끓여 먹거나 과자처럼 즐기기 좋은 건강 간식\n💰 공장 직판가로 만나는 대용량 가성비 팩\n▶ 구매하기', '', 1620000.00, 8100),
(11439, 1, '🍜 일본 현지의 맛, 돈코츠 라멘 밀키트', '', '🍜 진하게 우려낸 돼지 사골의 깊고 구수한 맛\n✨ 차슈와 죽순 토핑이 들어있어 완벽합니다\n📌 15분 만에 완성하는 고품격 면 요리\n▶ 겟하기', '', 1010000.00, 5050),
(11440, 1, '🥣 부드럽고 달콤한 단호박죽 5팩 세트', '', '🎃 단호박 원물을 통째로 갈아 넣어 진한 풍미\n💎 바쁜 아침, 간편하게 데워 건강하게 시작하세요\n💰 10팩 이상 구매 시 20% 특별 할인 혜택\n▶ 쇼핑하기', '', 400000.00, 2000),
(11441, 1, '🥘 밥도둑 1순위! 매콤 짭짤한 묵은지 조림', '', '🐟 고등어와 묵은지의 환상적인 조합이 일품\n✨ 엄마 손맛이 그리울 때 생각나는 바로 그 맛\n📌 따끈한 쌀밥 위에 얹어 먹으면 꿀맛 보장\n▶ 구매하기', '', 1690000.00, 8450),
(11442, 1, '🥨 천연 발효종으로 만든 무설탕 호밀빵', '', '🥖 건강을 생각한 정직하고 담백한 식사 빵\n✨ 고소한 호밀의 맛과 쫄깃한 식감이 특징입니다\n💰 당일 구워 당일 발송하는 신선 배송 시스템\n▶ 예약하기', '', 1080000.00, 5400),
(11443, 1, '🥩 숯불향 가득한 돼지 양념 갈비 1kg', '', '🔥 특제 양념에 숙성해 입안에서 녹는 부드러움\n✨ 아이들도 정말 좋아하는 단짠단짠의 정석\n💰 캠핑이나 여행 갈 때 챙겨가기 좋은 구성\n▶ 주문하기', '', 470000.00, 2350),
(11444, 1, '🍹 상큼한 비타민 충전, 레몬청 원액', '', '🍋 신선한 레몬으로 직접 담근 수제 원액\n✨ 시원한 레몬에이드나 따뜻한 레몬차로 즐기세요\n🎁 선물용 상자 포장 서비스 기본 제공 중\n▶ 확인하기', '', 1760000.00, 8800),
(11445, 1, '🍣 입안에서 살살 녹는 대뱃살 참치회', '', '🌊 최고급 참다랑어 오도로만 엄선했습니다\n💎 집에서 즐기는 럭셔리한 참치 파티 세트\n🚀 초저온 냉동 배송으로 신선함을 유지합니다\n▶ 주문하기', '', 1150000.00, 5750),
(11446, 1, '🥟 겉은 바삭 속은 촉촉한 수제 튀김만두', '', '🥟 당면과 야채가 꽉 찬 옛날식 튀김만두 맛\n✨ 떡볶이나 비빔면과 곁들이면 환상 궁합\n💰 3봉 세트 구매 시 전용 간장 소스 증정\n▶ 담으러 가기', '', 540000.00, 2700),
(11447, 1, '🍲 원기 회복의 정석! 명품 전복 삼계탕', '', '✨ 통전복이 들어간 프리미엄 보양 밀키트\n🔥 오랜 시간 고아낸 진한 육수의 깊은 맛\n📌 부모님 건강 선물로 이보다 좋을 수 없다\n▶ 구매하기', '', 1830000.00, 9150),
(11448, 1, '🍝 풍미 가득한 명란 크림 파스타', '', '🐚 고소한 크림 소스와 짭조름한 명란의 만남\n✨ 10분 만에 셰프의 요리를 완성해 보세요\n💰 런칭 기념 기간 한정 30% 파격 세일\n▶ 보러가기', '', 1220000.00, 6100),
(11449, 1, '🥨 시나몬 향이 가득한 츄러스 프레첼', '', '🍫 달콤한 시나몬 슈가가 듬뿍 뿌려진 별미\n✨ 오후의 나른함을 깨워줄 최고의 간식 아이템\n🎯 선착순 100명 1+1 이벤트 참여하기\n▶ 겟하세요', '', 610000.00, 3050),
(11450, 1, '🍱 정갈하고 든든한 12첩 반상 도시락', '', '🍱 매일 바뀌는 신선한 반찬으로 질릴 틈 없어요\n✨ 영양 균형을 맞춘 건강한 식단을 만나보세요\n💰 직장인 월 정기 결제 시 추가 적립 혜택\n▶ 주문하기', '', 1900000.00, 9500);
