INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(11451, 1, '🔥 맵부심 소환! 화끈한 지옥 불냉면', '', '✨ 눈물 쏙 빼는 매운맛과 시원한 육수의 만남\n💎 스트레스 풀고 싶은 날, 도전해보세요\n📌 겨자와 식초 없이도 완벽한 비법 양념\n▶ 도전하기', '', 1290000.00, 6450),
(11452, 1, '🍰 입안의 작은 사치, 마카롱 10구 세트', '', '💖 뚱카롱 부럽지 않은 필링의 진한 풍미\n✨ 꼬끄의 쫀득함과 부드러운 크림의 조화\n💰 선물용 보냉백 무료 증정 이벤트 중\n▶ 달콤함 충전', '', 680000.00, 3400),
(11453, 1, '🍣 입에서 사르르! 숙성 대도미회', '', '🌊 저온 숙성으로 감칠맛을 극대화했습니다\n💎 쫄깃한 껍질 식감까지 살린 마스카와 방식\n🚀 오늘 주문 시 내일 새벽 식탁으로 배송\n▶ 신선 배송 신청', '', 1970000.00, 9850),
(11454, 1, '🍜 비 오는 날 생각나는 얼큰 장칼국수', '', '🥢 강원도 정통 레시피로 만든 구수한 국물\n✨ 쑥갓과 김 가루 고명이 포함된 알찬 구성\n💰 3인분 세트 구매 시 배송비 전액 면제\n▶ 겟하세요', '', 1360000.00, 6800),
(11455, 1, '🥗 단백질 밸런스! 오리 훈제 샐러드', '', '🥑 불포화지방산 풍부한 오리 고기와 신선 채소\n✨ 유자 드레싱으로 상큼하게 마무리하세요\n🎯 식단 관리의 즐거움, 정기 구독 서비스\n▶ 식단 보기', '', 750000.00, 3750),
(11456, 1, '🥘 정통 프랑스식 가정식, 비프 부르기뇽', '', '🇫🇷 와인에 푹 고아낸 소고기의 부드러운 감동\n✨ 매쉬드 포테이토와 곁들이면 환상 궁합\n📌 특별한 홈파티를 위한 셰프의 밀키트\n▶ 메뉴 보기', '', 140000.00, 700),
(11457, 1, '🍗 마늘 치킨의 원조! 단양 마늘 통닭', '', '✨ 통마늘이 아낌없이 들어간 건강한 알싸함\n🔥 깨끗한 기름으로 튀겨 고소함이 남다릅니다\n💰 평일 주문 시 콜라 사이즈업 혜택 제공\n▶ 주문하기', '', 1430000.00, 7150),
(11458, 1, '🥤 100% 리얼 자몽 착즙 주스 1L', '', '🍊 쌉싸름하고 달콤한 자몽 생과일 그대로\n✨ 인공 첨가물 없는 순수한 비타민 충전\n🎁 3병 세트 구매 시 예쁜 유리 보틀 증정\n▶ 구매하기', '', 820000.00, 4100),
(11459, 1, '🥘 입맛 당기는 쫄깃한 소염통 구이', '', '🔥 잡내 없이 깔끔하게 손질된 프리미엄 육질\n✨ 고소한 기름장에 찍어 먹으면 안주로 최고\n📌 캠핑장 바비큐 메뉴로 강력 추천드립니다\n▶ 주문하기', '', 210000.00, 1050),
(11460, 1, '🥯 대파가 콕콕! 수제 대파 베이글', '', '🥯 구운 대파의 향긋한 풍미가 가득한 별미\n✨ 크림치즈와 베이컨을 곁들여 즐기세요\n💰 마감 직전 30% 선착순 타임 세일 진행\n▶ 쇼핑하기', '', 1500000.00, 7500),
(11461, 1, '🍲 엄마가 끓여준 맛, 황태 해장국', '', '✨ 뽀얗게 우려낸 국물이 일품인 속풀이 국\n🔥 술 마신 다음 날 시원하게 한 그릇 하세요\n📌 3분이면 완성되는 간편 보양식 패키지\n▶ 구매하기', '', 890000.00, 4450),
(11462, 1, '🍢 고소한 가래떡 구이와 조청 세트', '', '🍡 겉은 바삭하고 속은 말랑한 추억의 간식\n✨ 달콤한 조청에 찍어 먹으면 세상 행복\n💰 아이들 영양 간식 대용량 할인 판매 중\n▶ 겟하세요', '', 280000.00, 1400),
(11463, 1, '🍛 깊고 진한 맛의 비프 하야시라이스', '', '🇯🇵 데미글라스 소스의 풍미를 극대화했습니다\n✨ 소고기가 큼직하게 들어있어 식감이 훌륭함\n🎯 바쁜 아침 든든하게 채워주는 간편 한 끼\n▶ 확인하기', '', 1570000.00, 7850),
(11464, 1, '🥨 바삭하고 달콤한 메이플 프레첼', '', '🥨 메이플 시럽 코팅으로 더 향긋하고 달콤하게\n✨ 커피 타임에 곁들이기 좋은 핑거 푸드\n💰 온라인 단독! 1+1 창고 방출 찬스\n▶ 예약하기', '', 960000.00, 4800),
(11465, 1, '🦞 수율 보장! 명품 영덕 대게 3마리', '', '🌊 꽉 찬 속살과 고소한 내장의 깊은 맛\n💎 산지 직송으로 살아있는 신선함을 배송합니다\n🔥 시즌 종료 전 마지막 특가 기획전 운영 중\n▶ 주문하기', '', 350000.00, 1750),
(11466, 1, '🥟 육즙 가득 수제 고기 굴림만두', '', '🥟 만두피가 거의 없어 재료 본연의 맛이 가득\n✨ 전골이나 찜으로 다양하게 활용 가능합니다\n💰 1kg 대용량 구매 시 무료 배송 혜택\n▶ 더 보기', '', 1640000.00, 8200),
(11467, 1, '🥦 새벽 수확! 싱싱한 청경채 1kg', '', '🚜 밭에서 갓 따온 싱그러운 신선함 그대로\n✨ 샤브샤브나 볶음 요리에 필수 식재료입니다\n💰 유통 단계 축소로 마트보다 저렴한 가격\n▶ 신청하기', '', 1030000.00, 5150),
(11468, 1, '🥘 매콤 짭짤한 춘천식 제육 닭갈비', '', '🔥 닭다리살과 돼지 전지의 환상적인 콜라보\n✨ 깻잎과 고구마가 듬뿍 들어간 푸짐한 구성\n📌 주말 저녁 가족 외식 메뉴로 안성맞춤\n▶ 주문하기', '', 420000.00, 2100),
(11469, 1, '☕ 은은한 향기! 콜롬비아 수프리모', '', '✨ 호불호 없는 마일드한 커피의 대명사\n💎 아침을 여는 부드러운 향기를 느껴보세요\n💰 당일 로스팅 원두로 풍미를 보장합니다\n▶ 구매하기', '', 1710000.00, 8550),
(11470, 1, '🥪 아삭한 식감의 참치 마요 샌드위치', '', '🥗 고소한 참치 마요네즈와 신선한 야채의 만남\n✨ 간편하게 들고 먹기 좋은 피크닉 도시락\n🎯 단체 행사 예약 시 음료 무료 제공 혜택\n▶ 문의하기', '', 1100000.00, 5500),
(11471, 1, '🍲 구수함의 끝판왕! 차돌 된장찌개', '', '✨ 차돌박이를 넣어 국물 맛이 더 진하고 고소해요\n🔥 밥에 슥슥 비벼 먹기 좋은 자작한 국물\n📌 10분 완성 밀키트로 캠핑 요리 해결하세요\n▶ 선물하기', '', 490000.00, 2450),
(11472, 1, '🥩 육즙 가득! 프리미엄 돈마호크 구이', '', '🐷 돼지 한 마리에서 소량 나오는 귀한 부위\n✨ 고소한 지방과 담백한 살코기의 황금 비율\n💰 오늘 구매 시 특제 시즈닝 소스 증정\n▶ 쇼핑하기', '', 1780000.00, 8900),
(11473, 1, '🥣 영양 만점! 부드러운 잣죽 5팩', '', '💎 국내산 잣을 듬뿍 갈아 넣어 고소한 풍미\n✨ 소화가 잘 되어 아침 식사 대용으로 강력 추천\n📌 멸균 포장으로 상온에서도 보관이 간편해요\n▶ 확인하기', '', 1170000.00, 5850),
(11474, 1, '🍡 말랑말랑 쫀득한 수제 인절미 세트', '', '💖 콩고물이 듬뿍 묻어 고소함이 두 배입니다\n✨ 굳지 않는 공법으로 만든 쫄깃한 식감\n🎁 감사한 분께 마음을 전하는 선물용 포장 가능\n▶ 더 보기', '', 560000.00, 2800),
(11475, 1, '🍕 페퍼로니 폭탄 뉴욕 스타일 피자', '', '🧀 빈틈없이 꽉 채운 페퍼로니의 짭짤한 매력\n🔥 얇고 바삭한 도우로 끝까지 맛있게 드세요\n💰 방문 포장 시 현장 5,000원 즉시 할인\n▶ 주문하기', '', 1850000.00, 9250),
(11476, 1, '🍝 명란 가득! 들기름 파스타 밀키트', '', '🌿 짭조름한 명란과 고소한 들기름의 환상 궁합\n✨ 퓨전 이탈리안 요리를 집에서 10분 만에 완성\n📌 입맛 없는 날, 별미로 즐기기 딱 좋습니다\n▶ 구매하기', '', 1240000.00, 6200),
(11477, 1, '🍲 바다 향 가득! 신선한 홍합탕', '', '🌊 해캄 완료! 깨끗하게 손질된 홍합이 듬뿍\n✨ 청양고추 넣어 칼칼하게 끓이면 안주로 최고\n💰 9,900원의 가성비 끝판왕 해산물 팩\n▶ 겟하세요', '', 630000.00, 3150),
(11478, 1, '🍗 부드러운 안심 치킨 텐더 1kg', '', '🔥 닭 안심살만 사용하여 담백하고 촉촉한 맛\n✨ 아이들 간식이나 샐러드 토핑으로 인기 만점\n📌 리뷰 작성 시 전용 소스 2종 무료 증정\n▶ 바로가기', '', 1920000.00, 9600),
(11479, 1, '🍹 상큼 달콤! 샤인머스캣 에이드 원액', '', '🍇 귀한 샤인머스캣 과즙을 아낌없이 담았습니다\n✨ 탄산수만 부으면 고급 에이드 전문점 탄생\n💰 2병 구매 시 전용 보틀 추가 증정 이벤트\n▶ 쇼핑하기', '', 1310000.00, 6550),
(11480, 1, '🍳 입안에서 녹는 수플레 팬케이크 세트', '', '✨ 구름처럼 폭신한 식감의 정통 팬케이크\n💎 메이플 시럽과 생크림이 모두 포함된 구성\n📌 주말 아침, 브런치 카페 분위기를 내보세요\n▶ 구경하기', '', 700000.00, 3500),
(11481, 1, '🥘 화끈하게 매운 양념 코다리 조림', '', '🐟 살이 꽉 찬 명품 코다리와 비법 매콤 양념\n✨ 시래기와 감자를 넣어 더 풍성한 맛입니다\n💰 오늘 하루 선착순 배송비 면제 혜택\n▶ 주문하기', '', 1990000.00, 9950),
(11482, 1, '🍩 꾸덕한 크림치즈가 듬뿍! 수제 도넛', '', '💖 크림치즈가 빈틈없이 꽉 찬 달콤 짭짤함\n✨ 커피 한 잔과 함께하는 여유로운 휴식 시간\n🎯 단체 예약 시 개별 맞춤 스티커 서비스\n▶ 메뉴 보기', '', 1380000.00, 6900),
(11483, 1, '🍲 진한 사골 육수의 사골 우거지국', '', '✨ 48시간 고아낸 진국 육수와 구수한 우거지\n🔥 뜨끈하게 데워 밥 말아 먹으면 보약이 따로 없음\n📌 간편하게 보관 가능한 파우치 형태 제품\n▶ 겟하기', '', 770000.00, 3850),
(11484, 1, '🥨 달콤하고 고소한 아몬드 프레첼 칩', '', '🥨 슬라이스 아몬드가 듬뿍 뿌려진 바삭한 맛\n✨ 영화 정주행할 때 필수인 영양 간식 아이템\n💰 3봉 세트 구매 시 10% 추가 할인 적용\n▶ 확인하기', '', 160000.00, 800),
(11485, 1, '🥩 1++ 등급 한우 등심 정기 배송', '', '🥩 매주 엄선된 최상의 한우만 문 앞까지 배송\n✨ 특별한 날을 위한 최고의 육질을 약속합니다\n💰 구독 첫 달 한우 국거리 고기 서비스 증정\n▶ 신청하기', '', 1450000.00, 7250),
(11486, 1, '🥗 신선한 훈제 연어와 케이퍼 샐러드', '', '🐟 풍미 가득한 훈제 연어와 아삭한 채소의 만남\n✨ 홀스래디쉬 드레싱으로 깔끔하게 즐기세요\n📌 바쁜 아침, 든든하고 가벼운 한 끼 식사\n▶ 더 보기', '', 840000.00, 4200),
(11487, 1, '🍲 마라 매니아 필수! 마라탕 밀키트', '', '🔥 얼얼한 마라 소스와 풍성한 건더기의 조화\n✨ 소고기, 완자, 당면까지 풀세트로 준비 완료\n💰 오늘 주문 시 무알콜 맥주 1캔 서비스\n▶ 주문하기', '', 230000.00, 1150),
(11488, 1, '🍘 고소한 보리 누룽지 2kg 대용량', '', '✨ 국내산 보리로 만들어 더 구수하고 건강한 맛\n📌 아침 식사 대용이나 간식으로 쟁여두기 좋음\n💰 유통 거품 뺀 가격으로 가성비 끝판왕 등극\n▶ 구매하기', '', 1520000.00, 7600),
(11489, 1, '🍜 일본 현지 느낌! 탄탄멘 밀키트', '', '🍜 고소한 땅콩 소스와 매콤한 국물의 만남\n✨ 쫄깃한 생면과 볶은 고기 토핑이 일품입니다\n📌 집에서 15분 만에 완성하는 미식 여행\n▶ 겟하기', '', 910000.00, 4550),
(11490, 1, '🥣 영양 가득 단팥죽과 새알심 7팩', '', '✨ 팥 본연의 진한 맛과 쫀득한 새알심의 조화\n💎 겨울철뿐 아니라 사계절 든든한 건강 간식\n💰 1주일 패키지 구매 시 전용 컵 증정\n▶ 쇼핑하기', '', 300000.00, 1500),
(11491, 1, '🥘 밥도둑 끝판왕! 갈치 조림 밀키트', '', '🐟 도톰한 갈치와 무의 시원한 맛이 어우러진 맛\n✨ 비법 양념장으로 비린내 없이 깔끔하게\n📌 15분만 끓이면 완성되는 명품 한식 요리\n▶ 구매하기', '', 1590000.00, 7950),
(11492, 1, '🥨 천연 발효종 건강빵 깜빠뉴 3종', '', '🥖 무설탕, 무버터로 만든 담백하고 건강한 맛\n✨ 씹을수록 고소한 풍미가 느껴지는 식사 빵\n💰 매일 아침 구워 신선하게 당일 발송해 드려요\n▶ 예약하기', '', 980000.00, 4900),
(11493, 1, '🥩 부드러운 육질의 한방 돼지 수육', '', '🔥 한방 재료로 삶아 잡내 없이 깔끔한 맛\n✨ 겉은 탱글하고 속은 촉촉한 황금 비율 수육\n💰 지금 주문 시 보쌈 김치 500g 추가 증정\n▶ 주문하기', '', 370000.00, 1850),
(11494, 1, '🍹 상큼함 충전! 오미자 원액 500ml', '', '🍒 다섯 가지 맛이 조화로운 건강한 달콤함\n✨ 에이드나 차로 즐기기 좋은 수제 청 제품\n🎁 2병 구매 시 선물용 프리미엄 박스 포장\n▶ 확인하기', '', 1660000.00, 8300),
(11495, 1, '🍣 입에서 살살 녹는 연어 대뱃살 필렛', '', '🌊 슈페리어 등급의 가장 고소한 부위만 엄선\n💎 홈파티나 기념일에 즐기는 럭셔리한 회 한 점\n🚀 아이스박스 풀패킹으로 선도를 유지합니다\n▶ 주문하기', '', 1050000.00, 5250),
(11496, 1, '🥟 겉바속촉 수제 야채 튀김만두', '', '🥟 신선한 야채가 듬뿍 들어간 옛날식 만두 맛\n✨ 분식 메뉴와 함께 먹으면 환상의 궁합을 자랑\n💰 3봉 세트 구매 시 비법 초간장 소스 증정\n▶ 담으러 가기', '', 440000.00, 2200),
(11497, 1, '🍲 원기 회복! 전복 한우 사골 삼계탕', '', '✨ 보양 식재료의 끝판왕들이 만난 프리미엄 요리\n🔥 부모님 기력 회복을 위한 최고의 효도 선물\n📌 가마솥 전통 방식으로 우려내 깊이가 다름\n▶ 구매하기', '', 1730000.00, 8650),
(11498, 1, '🍝 풍미 가득한 베이컨 까르보나라', '', '🐚 고소한 생크림과 베이컨의 풍부한 맛의 조화\n✨ 셰프의 레시피로 집에서 10분 만에 완성\n💰 런칭 기념 기간 한정 30% 특별 세일 진행 중\n▶ 보러가기', '', 1120000.00, 5600),
(11499, 1, '🥨 초코 칩이 콕콕! 프레첼 신제품', '', '🍫 진한 초콜릿 칩이 씹히는 달콤한 즐거움\n✨ 오후의 나른함을 깨워줄 최고의 디저트 타임\n🎯 오늘 주문 시 선착순 1+1 혜택 놓치지 마세요\n▶ 겟하세요', '', 510000.00, 2550),
(11500, 1, '🍱 정성 가득 정갈한 15첩 반상 도시락', '', '🍱 매일 신선한 재료로 준비하는 럭셔리한 한 끼\n✨ 한식 명인의 정성이 담긴 균형 잡힌 식단\n💰 직장인 정기 결제 시 추가 15% 포인트 적립\n▶ 주문하기', '', 1800000.00, 9000);
